'use strict';

var fs = require('fs');
var path = require('path');
var { AuditLog } = require('./log');

/**
 * SOC 2 Type II control mappings.
 */
var SOC2_CONTROLS = {
  CC6_1: { name: 'Logical Access', description: 'Access to data and systems is restricted to authorized users' },
  CC6_2: { name: 'System Operations', description: 'System operations are monitored for anomalies' },
  CC6_3: { name: 'Change Management', description: 'Changes are authorized, tested, and approved before deployment' },
  CC7_1: { name: 'Risk Assessment', description: 'Risks are identified and mitigated' },
  CC7_2: { name: 'Monitoring', description: 'System components are monitored for anomalies' },
  CC8_1: { name: 'Incident Response', description: 'Security incidents are identified and responded to' },
};

/**
 * ISO 27001 Annex A control mappings.
 */
var ISO27001_CONTROLS = {
  'A.9.2': { name: 'User Access Management', description: 'Formal access provisioning and de-provisioning' },
  'A.12.4': { name: 'Logging and Monitoring', description: 'Events are recorded and evidence is generated' },
  'A.12.5': { name: 'Control of Operational Software', description: 'Installation of software is controlled' },
  'A.14.2': { name: 'Security in Development', description: 'Security requirements in SDLC' },
  'A.16.1': { name: 'Incident Management', description: 'Consistent approach to security incidents' },
  'A.18.1': { name: 'Compliance', description: 'Compliance with legal and contractual requirements' },
};

/**
 * Map audit actions to SOC 2 controls.
 */
var ACTION_TO_SOC2 = {
  'agent_start': ['CC6_1', 'CC6_2'],
  'agent_stop': ['CC6_1', 'CC6_2'],
  'file_write': ['CC6_3', 'CC7_2'],
  'file_read': ['CC6_1'],
  'command_execute': ['CC6_3', 'CC7_2'],
  'deploy': ['CC6_3', 'CC8_1'],
  'policy_evaluate': ['CC7_1', 'CC7_2'],
  'approval_request': ['CC6_3'],
  'approval_resolve': ['CC6_3'],
  'test_run': ['CC6_3', 'CC7_1'],
};

/**
 * Map audit actions to ISO 27001 controls.
 */
var ACTION_TO_ISO = {
  'agent_start': ['A.9.2', 'A.12.4'],
  'agent_stop': ['A.9.2', 'A.12.4'],
  'file_write': ['A.12.5', 'A.14.2'],
  'file_read': ['A.9.2'],
  'command_execute': ['A.12.5', 'A.14.2'],
  'deploy': ['A.12.5', 'A.14.2'],
  'policy_evaluate': ['A.18.1'],
  'approval_request': ['A.9.2', 'A.16.1'],
  'approval_resolve': ['A.9.2', 'A.16.1'],
  'test_run': ['A.14.2'],
};

/**
 * Generate a SOC 2 Type II evidence report from audit log entries.
 *
 * @param {object[]} entries - Audit log entries
 * @param {object} [opts]
 * @param {string} [opts.projectName] - Project name for the report
 * @param {string} [opts.period] - Reporting period description
 * @returns {object} Structured SOC 2 report
 */
function generateSoc2Report(entries, opts) {
  opts = opts || {};
  var controlEvidence = {};

  // Initialize all controls
  Object.keys(SOC2_CONTROLS).forEach(function (id) {
    controlEvidence[id] = {
      control: SOC2_CONTROLS[id],
      evidenceCount: 0,
      sampleEntries: [],
    };
  });

  // Map entries to controls
  for (var i = 0; i < entries.length; i++) {
    var entry = entries[i];
    var controls = ACTION_TO_SOC2[entry.what] || [];
    for (var j = 0; j < controls.length; j++) {
      var cid = controls[j];
      if (controlEvidence[cid]) {
        controlEvidence[cid].evidenceCount++;
        if (controlEvidence[cid].sampleEntries.length < 5) {
          controlEvidence[cid].sampleEntries.push({
            seq: entry.seq,
            timestamp: entry.timestamp,
            who: entry.who,
            what: entry.what,
          });
        }
      }
    }
  }

  return {
    reportType: 'SOC2_TYPE_II',
    generatedAt: new Date().toISOString(),
    projectName: opts.projectName || 'Sognatore',
    period: opts.period || 'Current',
    totalAuditEntries: entries.length,
    controls: controlEvidence,
    chainIntegrity: null, // Caller should set after verifyChain()
  };
}

/**
 * Generate an ISO 27001 mapping report.
 */
function generateIso27001Report(entries, opts) {
  opts = opts || {};
  var controlEvidence = {};

  Object.keys(ISO27001_CONTROLS).forEach(function (id) {
    controlEvidence[id] = {
      control: ISO27001_CONTROLS[id],
      evidenceCount: 0,
      sampleEntries: [],
    };
  });

  for (var i = 0; i < entries.length; i++) {
    var entry = entries[i];
    var controls = ACTION_TO_ISO[entry.what] || [];
    for (var j = 0; j < controls.length; j++) {
      var cid = controls[j];
      if (controlEvidence[cid]) {
        controlEvidence[cid].evidenceCount++;
        if (controlEvidence[cid].sampleEntries.length < 5) {
          controlEvidence[cid].sampleEntries.push({
            seq: entry.seq,
            timestamp: entry.timestamp,
            who: entry.who,
            what: entry.what,
          });
        }
      }
    }
  }

  return {
    reportType: 'ISO27001',
    generatedAt: new Date().toISOString(),
    projectName: opts.projectName || 'Sognatore',
    period: opts.period || 'Current',
    totalAuditEntries: entries.length,
    controls: controlEvidence,
  };
}

/**
 * Generate a GDPR data processing record.
 */
function generateGdprReport(entries, opts) {
  opts = opts || {};

  // Extract unique data subjects (actors) and processing activities
  var subjects = {};
  var activities = {};
  var dataCategories = {};

  for (var i = 0; i < entries.length; i++) {
    var entry = entries[i];
    subjects[entry.who] = (subjects[entry.who] || 0) + 1;
    activities[entry.what] = (activities[entry.what] || 0) + 1;

    // Categorize data types from metadata
    if (entry.metadata) {
      if (entry.metadata.dataType) {
        dataCategories[entry.metadata.dataType] = true;
      }
      if (entry.metadata.containsPii) {
        dataCategories['personal_data'] = true;
      }
    }
  }

  return {
    reportType: 'GDPR_DATA_PROCESSING_RECORD',
    generatedAt: new Date().toISOString(),
    projectName: opts.projectName || 'Sognatore',
    controller: opts.controller || 'Organization',
    purposes: ['Autonomous software development', 'Quality assurance', 'Deployment'],
    legalBasis: 'Legitimate interest (automated software development)',
    dataSubjects: Object.keys(subjects).map(function (s) {
      return { id: s, activityCount: subjects[s] };
    }),
    processingActivities: Object.keys(activities).map(function (a) {
      return { activity: a, count: activities[a] };
    }),
    dataCategories: Object.keys(dataCategories),
    retentionPolicy: opts.retentionDays ? opts.retentionDays + ' days' : 'Project lifetime',
    securityMeasures: [
      'Hash-chain tamper evidence on audit log',
      'Policy-based access controls',
      'Data residency enforcement',
    ],
  };
}

/**
 * Export a report as JSON string.
 */
function exportReportJson(report) {
  return JSON.stringify(report, null, 2);
}

module.exports = {
  generateSoc2Report: generateSoc2Report,
  generateIso27001Report: generateIso27001Report,
  generateGdprReport: generateGdprReport,
  exportReportJson: exportReportJson,
  SOC2_CONTROLS: SOC2_CONTROLS,
  ISO27001_CONTROLS: ISO27001_CONTROLS,
  ACTION_TO_SOC2: ACTION_TO_SOC2,
  ACTION_TO_ISO: ACTION_TO_ISO,
};

'use strict';

/**
 * Sognatore Audit Trail - Public API
 *
 * Enterprise audit logging with tamper-evident hash chains,
 * compliance report generation, and data residency enforcement.
 *
 * Usage:
 *   var audit = require('./src/audit');
 *   audit.init('/path/to/project');
 *   audit.record({ who: 'agent-1', what: 'file_write', where: 'src/app.js', why: 'implement feature' });
 *   var result = audit.verifyChain();
 *   var report = audit.generateReport('soc2');
 *   var allowed = audit.checkProvider('anthropic', 'us');
 */

var { AuditLog } = require('./log');
var compliance = require('./compliance');
var { ResidencyController } = require('./residency');

var _log = null;
var _residency = null;
var _initialized = false;
var _projectDir = null;

/**
 * Initialize the audit trail system.
 */
function init(projectDir) {
  var dir = projectDir || process.cwd();
  if (_initialized && _projectDir === dir) return;
  if (_initialized) destroy();

  _projectDir = dir;
  _log = new AuditLog({ projectDir: dir });
  _residency = new ResidencyController({ projectDir: dir });
  _initialized = true;
}

/**
 * Record an audit entry.
 */
function record(entry) {
  if (!_initialized) init();
  return _log.record(entry);
}

/**
 * Verify the hash chain integrity.
 */
function verifyChain() {
  if (!_initialized) init();
  return _log.verifyChain();
}

/**
 * Generate a compliance report.
 * @param {string} type - 'soc2', 'iso27001', or 'gdpr'
 * @param {object} [opts] - Report options
 */
function generateReport(type, opts) {
  if (!_initialized) init();
  var entries = _log.readEntries();
  switch (type) {
    case 'soc2':
      return compliance.generateSoc2Report(entries, opts);
    case 'iso27001':
      return compliance.generateIso27001Report(entries, opts);
    case 'gdpr':
      return compliance.generateGdprReport(entries, opts);
    default:
      throw new Error('Unknown report type: ' + type + '. Supported: soc2, iso27001, gdpr');
  }
}

/**
 * Export a report as JSON string.
 */
function exportReport(type, opts) {
  var report = generateReport(type, opts);
  return compliance.exportReportJson(report);
}

/**
 * Check if a provider is allowed by data residency policy.
 */
function checkProvider(provider, region) {
  if (!_initialized) init();
  return _residency.checkProvider(provider, region);
}

/**
 * Check if air-gapped mode is enabled.
 */
function isAirGapped() {
  if (!_initialized) init();
  return _residency.isAirGapped();
}

/**
 * Read filtered audit entries.
 */
function readEntries(filter) {
  if (!_initialized) init();
  return _log.readEntries(filter);
}

/**
 * Get audit log summary.
 */
function getSummary() {
  if (!_initialized) init();
  return _log.getSummary();
}

/**
 * Flush pending entries to disk.
 */
function flush() {
  if (_log) _log.flush();
}

/**
 * Destroy audit trail (for testing).
 */
function destroy() {
  if (_log) _log.destroy();
  _log = null;
  _residency = null;
  _initialized = false;
  _projectDir = null;
}

module.exports = {
  init: init,
  record: record,
  verifyChain: verifyChain,
  generateReport: generateReport,
  exportReport: exportReport,
  checkProvider: checkProvider,
  isAirGapped: isAirGapped,
  readEntries: readEntries,
  getSummary: getSummary,
  flush: flush,
  destroy: destroy,
};

'use strict';

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const MAX_MEMORY_ENTRIES = 1000;
const HASH_ALGO = 'sha256';

class AuditLog {
  constructor(opts) {
    const projectDir = (opts && opts.projectDir) || process.cwd();
    this._logDir = (opts && opts.logDir) || path.join(projectDir, '.sognatore', 'audit');
    this._logFile = path.join(this._logDir, 'audit.jsonl');
    this._entries = [];
    this._lastHash = 'GENESIS';
    this._entryCount = 0;
    this._loadChainTip();
  }

  record(entry) {
    if (!entry || !entry.who || !entry.what) {
      throw new Error('Audit entry requires at least "who" and "what" fields');
    }
    var auditEntry = {
      seq: this._entryCount,
      timestamp: new Date().toISOString(),
      who: String(entry.who),
      what: String(entry.what),
      where: entry.where ? String(entry.where) : null,
      why: entry.why ? String(entry.why) : null,
      metadata: entry.metadata ? JSON.parse(JSON.stringify(entry.metadata)) : null,
      previousHash: this._lastHash,
      hash: null,
    };
    auditEntry.hash = this._computeHash(auditEntry);
    this._lastHash = auditEntry.hash;
    this._entryCount++;
    this._entries.push(auditEntry);
    if (this._entries.length >= MAX_MEMORY_ENTRIES) {
      this.flush();
    }
    return auditEntry;
  }

  flush() {
    if (this._entries.length === 0) return;
    if (!fs.existsSync(this._logDir)) {
      fs.mkdirSync(this._logDir, { recursive: true });
    }
    var lines = this._entries.map(function (e) { return JSON.stringify(e); }).join('\n') + '\n';
    fs.appendFileSync(this._logFile, lines, 'utf8');
    this._entries = [];
  }

  verifyChain() {
    this.flush();
    if (!fs.existsSync(this._logFile)) {
      return { valid: true, entries: 0, brokenAt: null, error: null };
    }
    var content = fs.readFileSync(this._logFile, 'utf8').trim();
    if (!content) {
      return { valid: true, entries: 0, brokenAt: null, error: null };
    }
    var lines = content.split('\n');
    var expectedPrevHash = 'GENESIS';
    var count = 0;
    for (var i = 0; i < lines.length; i++) {
      var entry;
      try { entry = JSON.parse(lines[i]); } catch (e) {
        return { valid: false, entries: count, brokenAt: i, error: 'Invalid JSON at line ' + i };
      }
      if (entry.previousHash !== expectedPrevHash) {
        return { valid: false, entries: count, brokenAt: i,
          error: 'Hash chain broken at entry ' + i };
      }
      var computedHash = this._computeHash(entry);
      if (computedHash !== entry.hash) {
        return { valid: false, entries: count, brokenAt: i,
          error: 'Hash mismatch at entry ' + i + ': entry has been tampered with' };
      }
      expectedPrevHash = entry.hash;
      count++;
    }
    return { valid: true, entries: count, brokenAt: null, error: null };
  }

  readEntries(filter) {
    this.flush();
    if (!fs.existsSync(this._logFile)) return [];
    var content = fs.readFileSync(this._logFile, 'utf8').trim();
    if (!content) return [];
    var entries = content.split('\n').map(function (line) {
      try { return JSON.parse(line); } catch (_) { return null; }
    }).filter(Boolean);
    if (filter) {
      if (filter.who) entries = entries.filter(function (e) { return e.who === filter.who; });
      if (filter.what) entries = entries.filter(function (e) { return e.what === filter.what; });
      if (filter.since) entries = entries.filter(function (e) { return e.timestamp >= filter.since; });
      if (filter.until) entries = entries.filter(function (e) { return e.timestamp <= filter.until; });
    }
    return entries;
  }

  getSummary() {
    var entries = this.readEntries();
    var actors = {};
    var actions = {};
    for (var i = 0; i < entries.length; i++) {
      actors[entries[i].who] = true;
      actions[entries[i].what] = true;
    }
    return {
      totalEntries: entries.length,
      actors: Object.keys(actors),
      actions: Object.keys(actions),
      firstEntry: entries.length > 0 ? entries[0].timestamp : null,
      lastEntry: entries.length > 0 ? entries[entries.length - 1].timestamp : null,
    };
  }

  destroy() {
    this.flush();
    this._entries = [];
  }

  _computeHash(entry) {
    var data = JSON.stringify({
      seq: entry.seq, timestamp: entry.timestamp, who: entry.who,
      what: entry.what, where: entry.where, why: entry.why,
      metadata: entry.metadata, previousHash: entry.previousHash,
    });
    return crypto.createHash(HASH_ALGO).update(data).digest('hex');
  }

  _loadChainTip() {
    if (!fs.existsSync(this._logFile)) return;
    try {
      var content = fs.readFileSync(this._logFile, 'utf8').trim();
      if (!content) return;
      var lines = content.split('\n');
      var lastLine = lines[lines.length - 1];
      var lastEntry = JSON.parse(lastLine);
      this._lastHash = lastEntry.hash;
      this._entryCount = (lastEntry.seq || 0) + 1;
    } catch (_) {
      console.warn('[audit] Warning: corrupted chain tip detected, starting fresh chain');
      this._chainCorrupted = true;
    }
  }
}

module.exports = { AuditLog, HASH_ALGO, MAX_MEMORY_ENTRIES };

'use strict';

var fs = require('fs');
var path = require('path');

/**
 * Default allowed providers when no config exists.
 * Empty array means all providers allowed (no restriction).
 */
var DEFAULT_ALLOWED_PROVIDERS = [];

/**
 * Known provider regions for enforcement.
 */
var PROVIDER_REGIONS = {
  'anthropic': ['us', 'eu'],
  'openai': ['us', 'eu', 'asia'],
  'google': ['us', 'eu', 'asia'],
  'ollama': ['local'],
};

/**
 * Data Residency Controller.
 *
 * Enforces allowed LLM providers and regions based on configuration.
 * Supports air-gapped mode with local-only providers (Ollama).
 *
 * Configuration is loaded from .sognatore/residency.json:
 * {
 *   "allowed_providers": ["anthropic", "ollama"],
 *   "allowed_regions": ["us", "eu"],
 *   "air_gapped": false
 * }
 */
class ResidencyController {
  /**
   * @param {object} [opts]
   * @param {string} [opts.projectDir] - Project root
   * @param {object} [opts.config] - Direct config override (for testing)
   */
  constructor(opts) {
    opts = opts || {};
    var projectDir = opts.projectDir || process.cwd();
    this._configPath = path.join(projectDir, '.sognatore', 'residency.json');
    this._config = opts.config || this._loadConfig();
  }

  /**
   * Check if a provider is allowed by the residency policy.
   *
   * @param {string} provider - Provider name (e.g., 'anthropic', 'openai', 'ollama')
   * @param {string} [region] - Region identifier (e.g., 'us', 'eu')
   * @returns {{ allowed: boolean, reason: string|null }}
   */
  checkProvider(provider, region) {
    if (!provider) {
      return { allowed: false, reason: 'Provider name is required' };
    }

    var p = String(provider).toLowerCase();

    // Air-gapped mode: only local providers
    if (this._config.air_gapped) {
      var isLocal = p === 'ollama' || p === 'local';
      return isLocal
        ? { allowed: true, reason: null }
        : { allowed: false, reason: 'Air-gapped mode: only local providers (ollama) allowed' };
    }

    // Check allowed providers list
    var allowedProviders = this._config.allowed_providers || [];
    if (allowedProviders.length > 0 && allowedProviders.indexOf(p) === -1) {
      return { allowed: false, reason: 'Provider "' + p + '" not in allowed list: ' + allowedProviders.join(', ') };
    }

    // Check region restrictions
    var allowedRegions = this._config.allowed_regions || [];
    if (allowedRegions.length > 0 && region) {
      var r = String(region).toLowerCase();
      if (allowedRegions.indexOf(r) === -1) {
        return { allowed: false, reason: 'Region "' + r + '" not in allowed list: ' + allowedRegions.join(', ') };
      }
    }

    return { allowed: true, reason: null };
  }

  /**
   * Get the current residency configuration.
   */
  getConfig() {
    return { allowed_providers: (this._config.allowed_providers || []).slice(), allowed_regions: (this._config.allowed_regions || []).slice(), air_gapped: this._config.air_gapped };
  }

  /**
   * Check if air-gapped mode is enabled.
   */
  isAirGapped() {
    return this._config.air_gapped === true;
  }

  /**
   * List allowed providers.
   */
  getAllowedProviders() {
    return (this._config.allowed_providers || []).slice();
  }

  /**
   * List allowed regions.
   */
  getAllowedRegions() {
    return (this._config.allowed_regions || []).slice();
  }

  /**
   * Reload configuration from disk.
   */
  reload() {
    this._config = this._loadConfig();
  }

  // -- Private --

  _loadConfig() {
    try {
      if (fs.existsSync(this._configPath)) {
        var raw = fs.readFileSync(this._configPath, 'utf8');
        var config = JSON.parse(raw);
        return {
          allowed_providers: Array.isArray(config.allowed_providers) ? config.allowed_providers.map(function(p) { return String(p).toLowerCase(); }) : [],
          allowed_regions: Array.isArray(config.allowed_regions) ? config.allowed_regions : [],
          air_gapped: config.air_gapped === true,
        };
      }
    } catch (_) { /* fall through to defaults */ }

    return {
      allowed_providers: DEFAULT_ALLOWED_PROVIDERS,
      allowed_regions: [],
      air_gapped: false,
    };
  }
}

module.exports = {
  ResidencyController: ResidencyController,
  PROVIDER_REGIONS: PROVIDER_REGIONS,
  DEFAULT_ALLOWED_PROVIDERS: DEFAULT_ALLOWED_PROVIDERS,
};

#!/usr/bin/env node
'use strict';

var fs = require('fs');
var path = require('path');
var AuditLog = require('./log').AuditLog;

var sognatoreDir = process.env.SOGNATORE_DIR || '.sognatore';
var pendingDir = path.join(process.cwd(), sognatoreDir, 'events', 'pending');
var lastProcessedFile = '';

var audit = new AuditLog({ projectDir: process.cwd() });

// Event type to audit mapping
var EVENT_TO_AUDIT = {
    'iteration_start': { what: 'iteration_start', why: 'RARV cycle iteration started' },
    'iteration_complete': { what: 'iteration_complete', why: 'RARV cycle iteration completed' },
    'session_start': { what: 'session_start', why: 'Sognatore session initialized' },
    'session_end': { what: 'session_end', why: 'Sognatore session terminated' },
    'phase_change': { what: 'phase_change', why: 'RARV phase transition' },
    'policy_denied': { what: 'policy_violation', why: 'Policy engine blocked action' },
    'policy_approval_required': { what: 'policy_approval', why: 'Policy requires approval' },
    'otel_span_start': null, // Skip OTEL internal events
    'otel_span_end': null,   // Skip OTEL internal events
};

function processEventFile(filepath) {
    try {
        var data = JSON.parse(fs.readFileSync(filepath, 'utf8'));
        var eventType = data.type;
        var payload = data.payload || {};

        // Check if this event type should be audited
        if (!(eventType in EVENT_TO_AUDIT)) {
            // Unknown event types get a generic audit entry
            audit.record({
                who: payload.provider || data.source || 'system',
                what: eventType,
                where: 'iteration:' + (payload.iteration || 'unknown'),
                why: 'Event recorded',
                metadata: payload,
            });
            return;
        }

        var mapping = EVENT_TO_AUDIT[eventType];
        if (!mapping) return; // null = skip

        audit.record({
            who: payload.provider || data.source || 'system',
            what: mapping.what,
            where: 'iteration:' + (payload.iteration || 'unknown'),
            why: mapping.why,
            metadata: payload,
        });
    } catch (e) {
        // Fire-and-forget: errors must not crash the subscriber
    }
}

function scanPendingEvents() {
    if (!fs.existsSync(pendingDir)) return;
    try {
        var files = fs.readdirSync(pendingDir)
            .filter(function(f) { return f.endsWith('.json'); })
            .sort();
        for (var i = 0; i < files.length; i++) {
            if (files[i] > lastProcessedFile) {
                processEventFile(path.join(pendingDir, files[i]));
                lastProcessedFile = files[i];
            }
        }
    } catch (e) { /* ignore */ }
}

// Export for testing
if (require.main === module) {
    // Poll every 500ms
    var pollInterval = setInterval(scanPendingEvents, 500);
    scanPendingEvents();

    function shutdown() {
        clearInterval(pollInterval);
        audit.flush();
        process.exit(0);
    }
    process.on('SIGTERM', shutdown);
    process.on('SIGINT', shutdown);
    console.log('[audit-subscriber] Started, watching ' + pendingDir);
} else {
    module.exports = {
        processEventFile: processEventFile,
        scanPendingEvents: scanPendingEvents,
        EVENT_TO_AUDIT: EVENT_TO_AUDIT,
        _setAudit: function(a) { audit = a; },
        _setPendingDir: function(d) { pendingDir = d; },
        _getLastProcessedFile: function() { return lastProcessedFile; },
        _resetState: function() { lastProcessedFile = ''; },
    };
}

import { execSync } from 'child_process';
import path from 'path';
import fs from 'fs-extra';
import { ToolResolver } from './ToolResolver.js';

export class ContextManager {
  private toolResolver: ToolResolver;

  constructor(private readonly cwd: string) {
    this.toolResolver = new ToolResolver(cwd);
  }

  /**
   * Generates a high-level map of the project, respecting .gitignore.
   * Optimized to prevent ENAMETOOLONG errors on Windows.
   */
  async getCodeMap(): Promise<string> {
    try {
      // Use git to list tracked files (fastest and cleanest)
      const files = execSync('git ls-files', { cwd: this.cwd }).toString().split('\n');
      
      const tree: Record<string, any> = {};
      const MAX_FILES = 100; // Cap for individual file listing before summarization
      
      const limitedFiles = files.filter(f => f.trim()).length > MAX_FILES 
        ? files.filter(f => f.trim()).slice(0, MAX_FILES) 
        : files.filter(f => f.trim());

      for (const f of limitedFiles) {
        const parts = f.split('/');
        let current = tree;
        for (const part of parts) {
          if (!current[part]) current[part] = {};
          current = current[part];
        }
      }

      let output = this.formatTree(tree);
      if (files.length > MAX_FILES) {
        output += `\n... [${files.length - MAX_FILES} additional files omitted for swarm performance] ...\n`;
      }
      return output;
    } catch {
      return 'Project map unavailable (Git repository not found).';
    }
  }

  /**
   * Summarizes a specific file for the prompt
   */
  async summarizeFile(filePath: string): Promise<string> {
    const fullPath = path.resolve(this.cwd, filePath);
    if (!(await fs.pathExists(fullPath))) return `File not found: ${filePath}`;

    const content = await fs.readFile(fullPath, 'utf8');
    const lines = content.split('\n');
    
    // Performance cap: don't pass more than 10KB per file summary
    if (content.length > 10000) {
      return `[FILE TOO LARGE: ${Math.round(content.length/1024)}KB] - Summarizing head/tail only.\n` + 
        [...lines.slice(0, 30), '\n... [truncated] ...\n', ...lines.slice(-30)].join('\n');
    }

    if (lines.length < 50) return content;

    return [
      ...lines.slice(0, 20),
      `\n... [${lines.length - 40} lines omitted] ...\n`,
      ...lines.slice(-20)
    ].join('\n');
  }

  private formatTree(tree: any, indent = '', depth = 0): string {
    if (depth > 5) return `${indent}... [Deep structure truncated] ...\n`;
    
    let output = '';
    const keys = Object.keys(tree).sort();
    for (const key of keys) {
      const children = tree[key];
      const isDir = Object.keys(children).length > 0;
      output += `${indent}${isDir ? '📁' : '📄'} ${key}\n`;
      if (isDir) {
        output += this.formatTree(children, indent + '  ', depth + 1);
      }
    }
    return output;
  }
}

import { execa } from 'execa';
import chalk from 'chalk';
import os from 'os';
import { ProviderFactory } from './ProviderFactory.js';
import { ToolResolver } from './ToolResolver.js';

export interface DoctorResult {
  name: string;
  status: 'PASS' | 'FAIL' | 'WARN';
  version?: string;
  message?: string;
  required: boolean;
}

export class Doctor {
  private toolResolver = new ToolResolver(process.cwd());

  async checkAll(): Promise<DoctorResult[]> {
    const results: DoctorResult[] = [];

    // Basic Tools
    results.push(await this.checkCommand('Node.js', 'node', true, '>=18.0.0'));
    results.push(await this.checkCommand('Python 3', 'python', true, '>=3.8.0'));
    results.push(await this.checkCommand('Git', 'git', true));
    
    // AI Providers
    await this.checkProviders(results);

    // Development Tools (Gate Prerequisites)
    results.push(await this.checkCommand('ESLint', 'eslint', false));
    results.push(await this.checkCommand('TypeScript', 'tsc', false));

    // Disk Space (rough check)
    results.push(this.checkDiskSpace());

    return results;
  }

  private async checkCommand(name: string, cmd: string, required: boolean, versionSpec?: string): Promise<DoctorResult> {
    const isPresent = await this.toolResolver.isAvailable(cmd);
    
    if (isPresent) {
      try {
        const resolved = this.toolResolver.resolve(cmd);
        const { stdout } = await execa(resolved, ['--version']);
        return {
          name,
          status: 'PASS',
          version: stdout.split('\n')[0].trim(),
          required
        };
      } catch {
        return { name, status: 'PASS', required };
      }
    }

    return {
      name,
      status: required ? 'FAIL' : 'WARN',
      message: `${name} is not installed locally or in PATH.`,
      required
    };
  }

  private async checkProviders(results: DoctorResult[]) {
    const providers = [
      ProviderFactory.getProvider('gemini'),
      ProviderFactory.getProvider('claude'),
      ProviderFactory.getProvider('aider')
    ];

    for (const p of providers) {
      const isPresent = await p.detect();
      let version = undefined;
      if (isPresent) {
        try { version = await p.version(); } catch {}
      }

      results.push({
        name: p.metadata.displayName,
        status: isPresent ? 'PASS' : 'WARN',
        version,
        message: isPresent ? undefined : `${p.metadata.cli} CLI not found.`,
        required: false
      });
    }
  }

  private checkDiskSpace(): DoctorResult {
    const freeMemGB = Math.round(os.freemem() / (1024 * 1024 * 1024));
    return {
      name: 'System RAM',
      status: freeMemGB > 1 ? 'PASS' : 'WARN',
      version: `${freeMemGB}GB free`,
      message: freeMemGB <= 1 ? 'Low memory might affect performance.' : undefined,
      required: false
    };
  }

  displayResults(results: DoctorResult[]) {
    console.log(chalk.bold('\nSognatore Doctor (Windows Native)'));
    console.log('Checking system prerequisites...\n');

    let allRequiredPassed = true;

    for (const r of results) {
      let statusStr = '';
      if (r.status === 'PASS') statusStr = chalk.green('  PASS  ');
      else if (r.status === 'FAIL') {
        statusStr = chalk.red('  FAIL  ');
        if (r.required) allRequiredPassed = false;
      } else statusStr = chalk.yellow('  WARN  ');

      const versionStr = r.version ? chalk.dim(` (${r.version})`) : '';
      console.log(`${statusStr} ${r.name}${versionStr}`);
      if (r.message && r.status !== 'PASS') {
        console.log(chalk.dim(`         └─ ${r.message}`));
      }
    }

    console.log('\n' + (allRequiredPassed 
      ? chalk.green('✔ System is ready for Sognatore.') 
      : chalk.red('✘ System is missing required prerequisites.')));
  }
}

import JavaScriptObfuscator from 'javascript-obfuscator';
import fs from 'fs-extra';
import path from 'path';
import crypto from 'crypto';

/**
 * Sognatore Guardian - The Security & Privacy Sentinel
 * Replaces Phoenix security logic with a native, integrated engine.
 */
export class Guardian {
  private static instance: Guardian;
  private readonly SECRET_KEY = process.env.GUARDIAN_SECRET || 'sognatore_master_key_2026';

  private constructor() {}

  public static getInstance(): Guardian {
    if (!Guardian.instance) {
      Guardian.instance = new Guardian();
    }
    return Guardian.instance;
  }

  /**
   * Performs advanced obfuscation on generated code to protect IP and avoid tracking.
   */
  public obfuscateCode(code: string): string {
    if (!this.analyzeSensitivity(code)) {
      console.log('[GUARDIAN] Code analyzed: Low sensitivity. Skipping heavy obfuscation.');
      return code;
    }

    console.log('[GUARDIAN] Sensitive logic detected! Shielding code...');
    try {
      const obfuscationResult = JavaScriptObfuscator.obfuscate(code, {
        compact: true,
        controlFlowFlattening: true,
        controlFlowFlatteningThreshold: 1, // Full protection
        deadCodeInjection: true,
        deadCodeInjectionThreshold: 0.4,
        debugProtection: true,
        disableConsoleOutput: true,
        identifierNamesGenerator: 'hexadecimal',
        numbersToExpressions: true,
        selfDefending: true,
        simplify: true,
        splitStrings: true,
        stringArray: true,
        stringArrayRotate: true,
        stringArrayShuffle: true,
        stringArrayThreshold: 1,
        unicodeEscapeSequence: true
      });
      return obfuscationResult.getObfuscatedCode();
    } catch (error) {
      console.error('[GUARDIAN] Obfuscation failed, returning original code as fallback.');
      return code;
    }
  }

  /**
   * Autonomously detects if code contains sensitive logic or secrets.
   */
  public analyzeSensitivity(code: string): boolean {
    const sensitivePatterns = [
      /algorithm/i, /logic/i, /secret/i, /key/i, /token/i, /password/i,
      /crypto/i, /auth/i, /payment/i, /pricing/i, /formula/i, /strategy/i,
      /db_conn/i, /apikey/i, /credential/i, /private/i,
      /\(\s*.*\s*\)\s*=>\s*\{.*[+\-*\/].*\}/, // Heuristic for arrow functions with math logic
      /class\s+\w+\s+\{.*(calc|eval|process|secure).*\}/is // Heuristic for logic classes
    ];

    return sensitivePatterns.some(pattern => pattern.test(code));
  }

  /**
   * Sanitizes prompts by removing path patterns and potential sensitive data.
   */
  public sanitizePrompt(prompt: string): string {
    let sanitized = prompt;
    
    // Obfuscate local paths (e.g., C:\Users\carle\ -> USER_ROOT\)
    const userRootPattern = new RegExp(path.join('C:', 'Users', '[^/\\\\]+'), 'gi');
    sanitized = sanitized.replace(userRootPattern, '<<PROTECTED_ROOT>>');

    // Remove specific potential markers of "AI Generated" if present
    sanitized = sanitized.replace(/As an AI engineer/gi, 'Directly');
    
    return sanitized;
  }

  /**
   * "Seals" the logs/state with a basic layer of protection.
   */
  public sealData(data: any): string {
    const json = JSON.stringify(data);
    const cipher = crypto.createCipheriv('aes-256-cbc', 
        crypto.scryptSync(this.SECRET_KEY, 'salt', 32), 
        Buffer.alloc(16, 0)
    );
    let encrypted = cipher.update(json, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    return encrypted;
  }

  public unsealData(encrypted: string): any {
    try {
      const decipher = crypto.createDecipheriv('aes-256-cbc', 
          crypto.scryptSync(this.SECRET_KEY, 'salt', 32), 
          Buffer.alloc(16, 0)
      );
      let decrypted = decipher.update(encrypted, 'hex', 'utf8');
      decrypted += decipher.final('utf8');
      return JSON.parse(decrypted);
    } catch (e) {
      return null;
    }
  }
}

import fs from 'fs-extra';
import path from 'path';
import chalk from 'chalk';
import { execa } from 'execa';
import dotenv from 'dotenv';

export class ProjectManager {
  private currentDir: string;

  constructor(dir: string = process.cwd()) {
    this.currentDir = dir;
    dotenv.config();
  }

  /**
   * Inicializa un nuevo proyecto Sognatore clonando el motor actual.
   */
  async initProject(targetName: string) {
    const targetPath = path.resolve(this.currentDir, targetName);

    if (fs.existsSync(targetPath)) {
      throw new Error(`La carpeta ${targetName} ya existe.`);
    }

    console.log(chalk.blue(`\n🚀 Inicializando nuevo ecosistema Sognatore en: ${targetPath}`));

    // 1. Crear estructura básica
    await fs.ensureDir(targetPath);

    // 2. Definir qué copiar (Opción B: Clonación Total)
    const itemsToCopy = [
      'src',
      'package.json',
      'tsconfig.json',
      'README.md',
      'GUIDE.md',
      '.gitignore'
    ];

    for (const item of itemsToCopy) {
      const source = path.join(this.currentDir, item);
      const dest = path.join(targetPath, item);
      if (fs.existsSync(source)) {
        await fs.copy(source, dest);
        console.log(chalk.dim(`   + Copiado: ${item}`));
      }
    }

    // 3. Crear carpeta de configuración de usuario inicial si no existe
    const resourcesSource = path.join(this.currentDir, 'resources');
    const resourcesDest = path.join(targetPath, 'resources');
    await fs.copy(resourcesSource, resourcesDest);

    // 4. Crear metadatos del proyecto
    const sognatoreMeta = path.join(targetPath, '.sognatore');
    await fs.ensureDir(sognatoreMeta);
    await fs.writeFile(
      path.join(sognatoreMeta, 'master_path'),
      this.currentDir
    );

    console.log(chalk.green(`\n✔ Proyecto ${targetName} creado con éxito.`));
    console.log(`Próximos pasos:\n1. cd ${targetName}\n2. npm install\n3. npm run start -- setup\n`);
  }

  /**
   * Actualiza el núcleo del proyecto actual desde el maestro.
   */
  async upgrade() {
    const masterPath = process.env.SOGNATORE_MASTER_PATH;
    if (!masterPath || !fs.existsSync(masterPath)) {
      throw new Error('No se ha definido SOGNATORE_MASTER_PATH en el .env o la ruta no existe.');
    }

    console.log(chalk.blue(`\n🔄 Sincronizando con el "Sognatore Maestro": ${masterPath}`));

    // 1. Crear Backup
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    const backupDir = path.join(this.currentDir, '.sognatore', 'backups', timestamp);
    await fs.ensureDir(backupDir);

    console.log(chalk.yellow(`\n📦 Creando backup de seguridad en: .sognatore/backups/${timestamp}`));
    await fs.copy(path.join(this.currentDir, 'src'), path.join(backupDir, 'src'));
    await fs.copy(path.join(this.currentDir, 'package.json'), path.join(backupDir, 'package.json'));

    // 2. Intentar Backup en la Nube (Git)
    try {
      if (fs.existsSync(path.join(this.currentDir, '.git'))) {
        console.log(chalk.dim('   ☁ Subiendo backup a la nube (Git)...'));
        await execa('git', ['add', '.sognatore/backups/'], { cwd: this.currentDir });
        await execa('git', ['commit', '-m', `Backup pre-upgrade: ${timestamp}`], { cwd: this.currentDir });
        await execa('git', ['push'], { cwd: this.currentDir });
        console.log(chalk.green('   ✔ Backup en la nube completado.'));
      }
    } catch (e) {
      console.log(chalk.red('   ⚠ Falló el backup en la nube (Git), pero el backup local es seguro.'));
    }

    // 3. Ejecutar Actualización (Sobrescribir Core)
    const coreItems = ['src', 'package.json', 'tsconfig.json'];
    for (const item of coreItems) {
      const source = path.join(masterPath, item);
      const dest = path.join(this.currentDir, item);
      if (fs.existsSync(source)) {
        await fs.copy(source, dest, { overwrite: true });
        console.log(chalk.dim(`   ⚡ Sincronizado: ${item}`));
      }
    }

    console.log(chalk.green('\n✔ Actualización del motor completada con éxito.'));
    console.log(chalk.bold('Recuerda ejecutar `npm install` si han cambiado las dependencias.\n'));
  }
}

import { BaseGate } from './gates/BaseGate.js';
import { StaticAnalysisGate } from './gates/StaticAnalysisGate.js';
import { BlindReviewGate } from './gates/BlindReviewGate.js';
import { AntiSycophancyGate } from './gates/AntiSycophancyGate.js';
import { CompatibilityGate } from './gates/CompatibilityGate.js';
import { CouncilEvidence, GateResult } from './gates/types.js';
import chalk from 'chalk';

export class QualityCouncil {
  private gates: BaseGate[];

  constructor(private readonly cwd: string) {
    this.gates = [
      new CompatibilityGate(cwd),    // NEW: Gate 10 (High Priority)
      new StaticAnalysisGate(cwd),
      new BlindReviewGate(cwd),
      new AntiSycophancyGate(cwd)    // NEW: Gate 7
    ];
  }

  async evaluate(evidence: CouncilEvidence): Promise<{ passed: boolean; results: GateResult[] }> {
    console.log(chalk.bold(`\n${chalk.cyan('⚖️')} Quality Council Evaluation (Iteration ${evidence.iterationCount})`));
    console.log(chalk.dim(`  Mode: ${process.env.SOGNATORE_QUALITY_TIER || 'Standard Assurance'}`));
    
    const results: GateResult[] = [];
    let allPassed = true;

    for (const gate of this.gates) {
      process.stdout.write(`  Running ${chalk.dim(gate.name)}... `);
      try {
        const result = await gate.run(evidence);
        results.push(result);

        if (result.status === 'PASS') {
          process.stdout.write(chalk.green('PASS\n'));
        } else {
          process.stdout.write(chalk.red('FAIL\n'));
          allPassed = false;
        }

        // Display findings for failed gates
        if (result.findings.length > 0) {
          result.findings.forEach(f => {
            const color = f.severity === 'CRITICAL' ? chalk.red : chalk.yellow;
            console.log(color(`    - [${f.severity}] ${f.message}`));
          });
        }
      } catch (error: any) {
        process.stdout.write(chalk.red('ERROR\n'));
        console.error(`    Error in gate ${gate.name}: ${error.message}`);
        allPassed = false;
      }
    }

    if (allPassed) {
      console.log(chalk.bold.green('\n✔ Quality Council: All gates passed. Project is stable.'));
    } else {
      console.log(chalk.bold.red('\n✘ Quality Council: Verification failed. Corrections required.'));
    }

    return { passed: allPassed, results };
  }
}

import fs from 'fs-extra';
import path from 'path';
import { fileURLToPath } from 'url';

export interface SognatoreState {
  sessionId: string;
  projectName: string;
  currentIteration: number;
  currentPhase: 'reason' | 'act' | 'reflect' | 'verify';
  status: 'active' | 'paused' | 'stopped' | 'error';
  startTime: string;
  totalTokens: number;
  totalCost: number;
}

export class StateStore {
  private sognatoreDir: string;
  private stateFile: string;

  constructor(baseDir: string = '.') {
    this.sognatoreDir = path.resolve(baseDir, '.sognatore');
    this.stateFile = path.join(this.sognatoreDir, 'state', 'session.json');
  }

  async init(projectName: string): Promise<SognatoreState> {
    await fs.ensureDir(this.sognatoreDir);
    await fs.ensureDir(path.join(this.sognatoreDir, 'state'));
    await fs.ensureDir(path.join(this.sognatoreDir, 'locks'));
    await fs.ensureDir(path.join(this.sognatoreDir, 'logs'));
    await fs.ensureDir(path.join(this.sognatoreDir, 'agents'));

    let state: SognatoreState;

    if (await fs.pathExists(this.stateFile)) {
      state = await fs.readJson(this.stateFile);
    } else {
      state = {
        sessionId: `session_${Date.now()}`,
        projectName,
        currentIteration: 1,
        currentPhase: 'reason',
        status: 'active',
        startTime: new Date().toISOString(),
        totalTokens: 0,
        totalCost: 0
      };
      await this.saveState(state);
    }

    return state;
  }

  async saveState(state: SognatoreState): Promise<void> {
    // Atomic write on Windows is safer via temp file + rename
    const tempFile = `${this.stateFile}.tmp`;
    await fs.writeJson(tempFile, state, { spaces: 2 });
    await fs.move(tempFile, this.stateFile, { overwrite: true });
  }

  async getLogPath(agentName: string, iteration: number): Promise<string> {
    const logDir = path.join(this.sognatoreDir, 'logs', `it${iteration}`);
    await fs.ensureDir(logDir);
    return path.join(logDir, `${agentName}.log`);
  }

  getSognatoreDir(): string {
    return this.sognatoreDir;
  }
}

import { execa, type ExecaChildProcess } from 'execa';
import chalk from 'chalk';
import fs from 'fs-extra';
import path from 'path';

export interface ExecutionOptions {
  cwd?: string;
  env?: NodeJS.ProcessEnv;
  logFile?: string;
  timeout?: number;
}

export class Supervisor {
  private activeProcesses: Map<string, ExecaChildProcess> = new Map();

  constructor() {
    // Handle Ctrl+C for clean process termination
    process.on('SIGINT', () => this.terminateAll('SIGINT'));
    process.on('SIGTERM', () => this.terminateAll('SIGTERM'));
  }

  async runAgent(agentName: string, command: string, args: string[], options: ExecutionOptions = {}): Promise<string> {
    const processId = `${agentName}_${Date.now()}`;
    
    console.log(chalk.blue(`\n[AGENT] Starting ${agentName}...`));
    
    const childProcess = execa(command, args, {
      cwd: options.cwd || process.cwd(),
      env: { ...process.env, ...options.env },
      timeout: options.timeout || 300000, // 5 min default
      all: true, // Buffer both stdout and stderr
    });

    this.activeProcesses.set(processId, childProcess);

    // Stream output to log file if provided
    if (options.logFile) {
      await fs.ensureDir(path.dirname(options.logFile));
      const logStream = fs.createWriteStream(options.logFile, { flags: 'a' });
      childProcess.all?.pipe(logStream);
    }

    try {
      const { all } = await childProcess;
      this.activeProcesses.delete(processId);
      return all || '';
    } catch (error: any) {
      this.activeProcesses.delete(processId);
      throw new Error(`Agent ${agentName} failed: ${error.message}`);
    }
  }

  terminateAll(signal: string) {
    if (this.activeProcesses.size === 0) return;

    console.log(chalk.yellow(`\n[SUPERVISOR] Terminating ${this.activeProcesses.size} active processes (${signal})...`));
    
    for (const [id, proc] of this.activeProcesses) {
      proc.kill(signal);
      this.activeProcesses.delete(id);
    }
  }
}

import { Agent } from './agents/Agent.js';
import { AgentRegistry } from './agents/AgentRegistry.js';
import { AgentSwarm } from './agents/AgentTypes.js';
import path from 'path';
import fs from 'fs';
import { EventEmitter } from 'events';

export interface SwarmTask {
  id: string;
  type: string;
  description: string;
  priority: number;
  swarm?: AgentSwarm;
  assignedTo?: string;
  status: 'pending' | 'active' | 'completed' | 'failed';
  result?: string;
}

export class SwarmOrchestrator extends EventEmitter {
  private static instance: SwarmOrchestrator;
  private messageBus: string;
  private taskQueue: SwarmTask[] = [];
  private registry: AgentRegistry;

  private constructor() {
    super();
    this.messageBus = path.join(process.cwd(), '.sognatore', 'messages');
    this.registry = AgentRegistry.getInstance();
    this.initFileSystem();
  }

  static getInstance(): SwarmOrchestrator {
    if (!SwarmOrchestrator.instance) {
      SwarmOrchestrator.instance = new SwarmOrchestrator();
    }
    return SwarmOrchestrator.instance;
  }

  private initFileSystem() {
    const dirs = [
      this.messageBus,
      path.join(this.messageBus, 'inbox'),
      path.join(this.messageBus, 'outbox'),
      path.join(this.messageBus, 'broadcast'),
      path.join(process.cwd(), '.sognatore', 'queue')
    ];
    
    dirs.forEach(dir => {
      if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    });
  }

  /**
   * Dispatches a task to the swarm.
   * Finds the best agent category and triggers parallel execution if enabled.
   */
  async dispatchTask(task: SwarmTask): Promise<string> {
    this.taskQueue.push(task);
    this.saveQueue();

    // In a high-assurance swarm, we find the specialist
    const agentType = this.resolveSpecialistForTask(task.type);
    const agent = await this.registry.getAgent(agentType);
    
    this.emit('task:started', { taskId: task.id, agentId: agent.id });
    
    try {
      const result = await agent.runTask(task.description);
      task.status = 'completed';
      task.result = result;
      this.saveQueue();
      
      this.emit('task:completed', { taskId: task.id, result });
      return result;
    } catch (error) {
      task.status = 'failed';
      this.saveQueue();
      throw error;
    }
  }

  /**
   * Broadcasts a message to all agents in the swarm.
   */
  async broadcast(message: string, sender: string) {
    const broadcastDir = path.join(this.messageBus, 'broadcast');
    const msgId = `${Date.now()}-${sender}.json`;
    
    fs.writeFileSync(path.join(broadcastDir, msgId), JSON.stringify({
      sender,
      timestamp: new Date().toISOString(),
      content: message
    }));
  }

  private resolveSpecialistForTask(taskType: string): string {
    // Simple mapping logic: task types often start with the agent prefix (e.g., 'ui-' -> eng-frontend)
    if (taskType.startsWith('ui-')) return 'eng-frontend';
    if (taskType.startsWith('api-')) return 'eng-backend';
    if (taskType.startsWith('db-')) return 'eng-database';
    if (taskType.startsWith('sec-')) return 'ops-security';
    if (taskType.startsWith('prd-')) return 'prod-pm';
    
    // Default to a general engineer if no match
    return 'eng-backend';
  }

  private saveQueue() {
    const queuePath = path.join(process.cwd(), '.sognatore', 'queue', 'pending.json');
    fs.writeFileSync(queuePath, JSON.stringify(this.taskQueue, null, 2));
  }
}

import { execSync } from 'child_process';
import fs from 'fs';
import path from 'path';
import chalk from 'chalk';

export interface ToolDefinition {
  name: string;
  description: string;
  parameters: Record<string, string>;
  execute: (args: any, agentTier: string) => Promise<string>;
}

export class ToolRegistry {
  private static instance: ToolRegistry;
  private tools: Map<string, ToolDefinition> = new Map();
  private protectedFiles: string[] = ['.env', '.git', 'node_modules', '.sognatore'];

  private constructor() {
    this.registerDefaultTools();
  }

  static getInstance(): ToolRegistry {
    if (!ToolRegistry.instance) {
      ToolRegistry.instance = new ToolRegistry();
    }
    return ToolRegistry.instance;
  }

  private registerDefaultTools() {
    // 1. fs_read
    this.register({
      name: 'fs_read',
      description: 'Lee el contenido de un archivo del disco.',
      parameters: { path: 'Ruta relativa del archivo' },
      execute: async (args, tier) => {
        const fullPath = path.resolve(process.cwd(), args.path);
        if (!fs.existsSync(fullPath)) return `ERROR: Archivo no encontrado en ${args.path}`;
        return fs.readFileSync(fullPath, 'utf8');
      }
    });

    // 2. fs_write
    this.register({
      name: 'fs_write',
      description: 'Crea o sobrescribe un archivo con el contenido proporcionado.',
      parameters: { path: 'Ruta relativa', content: 'Contenido del archivo' },
      execute: async (args, tier) => {
        const isProtected = this.protectedFiles.some(f => args.path.includes(f));
        if (isProtected && tier === 'silver') {
          return `SECURITY ERROR: El agente de nivel Plata no tiene permisos para modificar archivos protegidos (${args.path}).`;
        }
        
        const fullPath = path.resolve(process.cwd(), args.path);
        const dir = path.dirname(fullPath);
        if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
        
        fs.writeFileSync(fullPath, args.content);
        return `SUCCESS: Archivo ${args.path} escrito correctamente.`;
      }
    });

    // 3. fs_list
    this.register({
      name: 'fs_list',
      description: 'Lista los archivos de un directorio.',
      parameters: { path: 'Ruta relativa del directorio' },
      execute: async (args, tier) => {
        const fullPath = path.resolve(process.cwd(), args.path || '.');
        if (!fs.existsSync(fullPath)) return `ERROR: Directorio no encontrado.`;
        return fs.readdirSync(fullPath).join('\n');
      }
    });

    // 4. shell_exec
    this.register({
      name: 'shell_exec',
      description: 'Ejecuta un comando en la terminal de Windows.',
      parameters: { command: 'Comando a ejecutar' },
      execute: async (args, tier) => {
        // Bloqueo de seguridad preventivo
        const dangerousCommands = ['format', 'del /s /q c:', 'rmdir /s /q c:'];
        if (dangerousCommands.some(cmd => args.command.toLowerCase().includes(cmd))) {
          return `SECURITY ERROR: Comando bloqueado por el protocolo de seguridad de Sognatore.`;
        }

        try {
          const output = execSync(args.command, { encoding: 'utf8', timeout: 30000 });
          return output || 'SUCCESS: Comando ejecutado (sin salida)';
        } catch (error: any) {
          return `ERROR: ${error.message}\n${error.stdout || ''}`;
        }
      }
    });
  }

  public register(tool: ToolDefinition) {
    this.tools.set(tool.name, tool);
  }

  public async call(name: string, args: any, agentTier: string): Promise<string> {
    const tool = this.tools.get(name);
    if (!tool) return `ERROR: Herramienta "${name}" no encontrada.`;
    
    console.log(chalk.gray(`[TOOL] ${agentTier} executing ${name}...`));
    return await tool.execute(args, agentTier);
  }

  public getToolsDefinition(): string {
    let def = "Herramientas Disponibles (Usa el formato XML <tool_call>):\n\n";
    this.tools.forEach(t => {
      def += `- ${t.name}: ${t.description}\n`;
      def += `  Parámetros: ${JSON.stringify(t.parameters)}\n\n`;
    });
    return def;
  }
}

import { Provider } from '../Provider.js';
import { AgentRole } from './AgentTypes.js';
import { StateStore } from '../StateStore.js';
import path from 'path';
import fs from 'fs';
import chalk from 'chalk';
import { ToolRegistry } from '../actions/ToolRegistry.js';
import { AgentFactory } from './AgentFactory.js';
import { Guardian } from '../Guardian.js';

export interface AgentState {
  id: string;
  type: string;
  swarm: string;
  status: 'idle' | 'busy' | 'error';
  currentTask?: string;
  lastActive: string;
  stats: {
    tasksCompleted: number;
    tokensUsed: number;
  };
}

export class Agent {
  private state: AgentState;
  private statePath: string;

  constructor(
    public readonly id: string,
    public readonly role: AgentRole,
    public readonly provider: Provider,
    private model: string,
    private tier: string
  ) {
    this.statePath = path.join(process.cwd(), '.sognatore', 'state', 'agents', `${this.id}.json`);
    this.state = this.loadState();
  }

  public getProviderName(): string {
    return this.provider.getName();
  }

  async runTask(task: string): Promise<string> {
    this.updateStatus('busy', task);
    
    // Si es Claude, delegamos la autonomía a su CLI nativo (ya es agentico)
    if (this.provider.metadata.name === 'claude') {
      return this.executeAgenticTask(task);
    }

    // Para Gemini/GPT, implementamos el bucle RARV nativo de Sognatore
    return this.executeNativeLoop(task);
  }

  private async executeAgenticTask(task: string): Promise<string> {
    const systemPrompt = this.buildSystemPrompt();
    const sanitizedTask = Guardian.getInstance().sanitizePrompt(task);
    
    const result = await this.provider.invoke(sanitizedTask, {
      tier: 'development',
      model: this.model,
      system: systemPrompt
    });

    // Ofuscar si es código generado
    const finalResult = Guardian.getInstance().obfuscateCode(result);

    this.recordStats(systemPrompt.length + sanitizedTask.length, finalResult.length);
    this.updateStatus('idle');
    return finalResult;
  }

  private async executeNativeLoop(initialTask: string): Promise<string> {
    let currentPrompt = initialTask;
    let turn = 0;
    const maxTurns = 10;
    const history: string[] = [];
    const systemPrompt = this.buildSystemPrompt() + "\n\n" + ToolRegistry.getInstance().getToolsDefinition();

    console.log(chalk.blue(`[SOGNATORE-LOOP] Iniciando bucle agéntico para ${this.id} (${this.model})`));

    while (turn < maxTurns) {
      turn++;
      const fullPrompt = history.length > 0 
        ? `Task Context:\n${history.join('\n\n')}\n\nContinue Task: ${currentPrompt}`
        : currentPrompt;

      const sanitizedPrompt = Guardian.getInstance().sanitizePrompt(fullPrompt);

      const response = await this.provider.invoke(sanitizedPrompt, {
        tier: 'development',
        model: this.model,
        system: systemPrompt
      });

      this.recordStats(systemPrompt.length + fullPrompt.length, response.length);
      history.push(`> User: ${currentPrompt}`, `> Agent: ${response}`);

      // Parse XML Tool Calls
      const toolCallMatch = response.match(/<tool_call>([\s\S]*?)<\/tool_call>/);
      
      if (toolCallMatch) {
        const toolXml = toolCallMatch[1];
        const toolName = toolXml.match(/<tool_name>(.*?)<\/tool_name>/)?.[1];
        const paramsMatch = toolXml.match(/<parameters>([\s\S]*?)<\/parameters>/);
        
        if (toolName && paramsMatch) {
          const paramsXml = paramsMatch[1];
          const params: any = {};
          // Basic parameter extraction from XML-ish format
          const paramTags = paramsXml.match(/<(\w+)>(.*?)<\/\w+>/g);
          paramTags?.forEach(tag => {
            const m = tag.match(/<(\w+)>(.*?)<\/\w+>/);
            if (m) params[m[1]] = m[2];
          });

          // Execute Tool
          const observation = await ToolRegistry.getInstance().call(toolName, params, this.getAgentTier());
          history.push(`> Observation (${toolName}): ${observation}`);
          currentPrompt = `Observation from ${toolName}: ${observation}. Please decide your next step. If finished, reply with TASK_COMPLETE.`;
          continue;
        }
      }

      if (response.includes('TASK_COMPLETE') || turn >= maxTurns) {
        break;
      }
    }

    this.updateStatus('idle');
    return history[history.length - 1];
  }

  private recordStats(inputLen: number, outputLen: number) {
    const inputTokens = Math.ceil(inputLen / 4);
    const outputTokens = Math.ceil(outputLen / 4);
    
    // Report to central cost tracker
    import('../utils/CostTracker.js').then(m => {
      m.CostTracker.getInstance().calculateAndReport(this.model, inputTokens, outputTokens);
    });

    this.state.stats.tasksCompleted++;
    this.state.stats.tokensUsed += (inputTokens + outputTokens);
  }

  private getAgentTier(): string {
    return this.tier;
  }

  private buildSystemPrompt(): string {
    return `
# Agent Identity
You are **${this.role.type}** agent with ID **${this.id}**.
Swarm: ${this.role.swarm}
Model: ${this.model} (2026 Multimodelo Strategy)

## Your Capabilities
${this.role.capabilities.map(c => `- ${c}`).join('\n')}

## Your Task Types
${this.role.taskTypes.map(t => `- ${t}`).join('\n')}

## Quality Checks You Must Perform
${this.role.qualityChecks.map(q => `- ${q}`).join('\n')}

## Tool Use Protocol (XML REQUIRED)
If you need to perform an action, you MUST use the following XML format:
<tool_call>
  <tool_name>name_of_the_tool</tool_name>
  <parameters>
    <param_name>value</param_name>
  </parameters>
</tool_call>

Wait for the "Observation" from the system before proceeding. 
When the task is 100% finished, include the keyword TASK_COMPLETE in your final response.

## Your Constraints
- Only claim tasks matching your capabilities
- Always verify before assuming (web search, test code)
- Checkpoint state before major operations
- Log all decisions with reasoning

## Task Execution Loop (RARV)
1. Reason: Analyze the state and decide the next action
2. Act: Call the appropriate tool
3. Reflect: Analyze the tool's observation
4. Verify: Ensure the result matches the requirement
    `.trim();
  }

  private updateStatus(status: 'idle' | 'busy' | 'error', task?: string) {
    this.state.status = status;
    this.state.currentTask = task;
    this.state.lastActive = new Date().toISOString();
    this.saveState();
  }

  private saveState() {
    const dir = path.dirname(this.statePath);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    
    // Sellar los datos con el Guardian
    const sealedData = Guardian.getInstance().sealData(this.state);
    fs.writeFileSync(this.statePath, sealedData);
  }

  private loadState(): AgentState {
    if (fs.existsSync(this.statePath)) {
      const data = fs.readFileSync(this.statePath, 'utf8');
      const unsealed = Guardian.getInstance().unsealData(data);
      if (unsealed) return unsealed;
    }
    return {
      id: this.id,
      type: this.role.type,
      swarm: this.role.swarm,
      status: 'idle',
      lastActive: new Date().toISOString(),
      stats: { tasksCompleted: 0, tokensUsed: 0 }
    };
  }

  getMetadata() {
    return {
      id: this.id,
      type: this.role.type,
      swarm: this.role.swarm,
      model: this.model,
      provider: this.provider.metadata.name
    };
  }
}

import fs from 'fs';
import path from 'path';
import { Provider } from '../Provider.js';
import { ProviderFactory } from '../ProviderFactory.js';
import { AgentRole, AgentSwarm, AGENT_SWARM_MAPPING } from './AgentTypes.js';

interface TierInfo {
  display_name: string;
  description: string;
  models: Array<{ provider: string; model: string }>;
}

interface ModelStrategy {
  strategy_name: string;
  version: string;
  tiers: Record<string, TierInfo>;
  agent_tier_mapping: Record<string, string>;
  default_tier: string;
}

export class AgentFactory {
  private static instance: AgentFactory;
  private agentsMDPath: string;
  private availableProviders: Provider[] = [];

  private strategy: ModelStrategy | undefined;

  private constructor() {
    this.agentsMDPath = path.join(process.cwd(), 'resources', 'config', 'agents.md');
  }

  static async getInstance(): Promise<AgentFactory> {
    if (!AgentFactory.instance) {
      AgentFactory.instance = new AgentFactory();
      await AgentFactory.instance.init();
    }
    return AgentFactory.instance;
  }

  private async init() {
    this.availableProviders = await ProviderFactory.getAvailableProviders();
    const strategyPath = path.join(process.cwd(), 'resources', 'config', 'model_strategy.json');
    if (fs.existsSync(strategyPath)) {
      this.strategy = JSON.parse(fs.readFileSync(strategyPath, 'utf8'));
    }
  }

  /**
   * Returns a specific agent by type with the best available provider 
   * following the 2026 Tiered Efficiency Strategy.
   */
  async getAgent(type: string): Promise<{ role: AgentRole; provider: Provider; model: string; tier: string }> {
    const role = await this.parseAgentRole(type);
    const { provider, model, tier } = this.resolveProviderAndModel(type, role.swarm);
    
    return { role, provider, model, tier };
  }

  private resolveProviderAndModel(type: string, swarm: AgentSwarm): { provider: Provider; model: string; tier: string } {
    const tierName = this.strategy?.agent_tier_mapping[type] || 
                     this.strategy?.agent_tier_mapping[swarm] || 
                     this.strategy?.default_tier || 'gold';
    
    const tierInfo = this.strategy?.tiers[tierName];
    if (!tierInfo) throw new Error(`Model tier "${tierName}" not defined in model_strategy.json`);

    for (const entry of tierInfo.models) {
      const provider = this.availableProviders.find(p => p.metadata.name === entry.provider);
      if (provider) {
        return { provider, model: entry.model, tier: tierName };
      }
    }

    // Fallback logic if tier models are unavailable
    if (this.availableProviders.length > 0) {
      const fallback = this.availableProviders[0];
      return { provider: fallback, model: 'best', tier: 'gold' };
    }

    throw new Error('No AI providers available. Check your environment keys.');
  }

  private async parseAgentRole(type: string): Promise<AgentRole> {
    const content = fs.readFileSync(this.agentsMDPath, 'utf8');
    const sections = content.split('---');
    
    // Simple parser for agents.md specification
    for (const section of sections) {
      if (section.includes(`### ${type}`)) {
        const capabilitiesMatch = section.match(/\*\*Capabilities:\*\*\s*([\s\S]*?)(?=\*\*|$)/);
        const taskTypesMatch = section.match(/\*\*Task Types:\*\*\s*([\s\S]*?)(?=\*\*|$)/);
        const qualityChecksMatch = section.match(/\*\*Quality Checks:\*\*\s*([\s\S]*?)(?=\*\*|$)/);

        const swarm = this.getSwarmForAgent(type);

        return {
          type,
          swarm,
          capabilities: this.cleanList(capabilitiesMatch ? capabilitiesMatch[1] : ''),
          taskTypes: this.cleanList(taskTypesMatch ? taskTypesMatch[1] : ''),
          qualityChecks: this.cleanList(qualityChecksMatch ? qualityChecksMatch[1] : '')
        };
      }
    }

    throw new Error(`Agent type "${type}" not found in resources/config/agents.md`);
  }

  private getSwarmForAgent(type: string): AgentSwarm {
    for (const [swarm, agents] of Object.entries(AGENT_SWARM_MAPPING)) {
      if (agents.includes(type)) return swarm as AgentSwarm;
    }
    return 'orchestration';
  }

  private cleanList(text: string): string[] {
    return text
      .split('\n')
      .map(line => line.trim().replace(/^-\s*/, ''))
      .filter(line => line.length > 0);
  }
}

import { BaseGate } from './BaseGate.js';
import { GateResult, CouncilEvidence } from './types.js';
import { ProviderFactory } from '../ProviderFactory.js';
import chalk from 'chalk';

export class AntiSycophancyGate extends BaseGate {
  get id() { return 'QG-007'; }
  get name() { return 'Anti-Sycophancy (Devil\'s Advocate)'; }

  async run(evidence: CouncilEvidence): Promise<GateResult> {
    const available = await ProviderFactory.getAvailableProviders();
    const primaryName = process.env.SOGNATORE_PROVIDER || 'claude';
    
    // Strategy 1: Cross-Model Audit (Best)
    // Find a provider that is NOT the primary one
    let verifier = available.find(p => p.metadata.name !== primaryName);
    let strategy = 'Cross-Model Audit';

    // Strategy 2: Single-Model Blind Audit (Fallback)
    if (!verifier) {
      verifier = ProviderFactory.getProvider(primaryName);
      strategy = 'Single-Model Blind Audit';
    }

    const prompt = `
      ### INSTRUCTION: CRITICAL AUDIT REQUIRED ###
      You are the SOGNATORE DEVIL'S ADVOCATE. Your ONLY goal is to find reasons why the current implementation is WRONG, INCOMPLETE, or DANGEROUS.
      
      ${strategy === 'Single-Model Blind Audit' ? 'WARNING: Do not agree with previous reasoning. You will be penalized if you fail to find a valid criticism.' : ''}
      
      DIFF:
      ${evidence.gitDiff || 'No changes.'}
      
      PRD:
      ${evidence.prdPath || 'No PRD.'}

      ### YOUR TASK:
      1. Find at least one subtle bug or missing edge case.
      2. Analyze if the changes follow the PRD strictly.
      3. Check for "lazy" code (TODOs, mocks, missing error handles).

      ### RESPONSE FORMAT:
      VERDICT: [FAIL if you found a valid issue, PASS only if you are 100% sure it is perfect]
      CRITICISM: [Detail your findings here]
    `;

    try {
      const response = await verifier.invoke(prompt, { tier: 'planning' });
      const failMatch = response.includes('VERDICT: FAIL');
      const criticism = response.match(/CRITICISM:\s*(.*)/is)?.[1] || 'No specific criticism found.';

      if (failMatch) {
        return this.fail(criticism, 'HIGH', { strategy, response });
      }

      return this.pass({ strategy, response });
    } catch (e: any) {
      return this.fail(`Verification Error: ${e.message}`, 'MEDIUM');
    }
  }
}

import { GateResult, CouncilEvidence } from './types.js';
import { ToolResolver } from '../ToolResolver.js';

export abstract class BaseGate {
  protected toolResolver: ToolResolver;

  constructor(protected readonly cwd: string) {
    this.toolResolver = new ToolResolver(cwd);
  }

  abstract get id(): string;
  abstract get name(): string;

  /**
   * Main execution point for the gate.
   */
  abstract run(evidence: CouncilEvidence): Promise<GateResult>;

  /**
   * Helper to format a quick pass result.
   */
  protected pass(evidence?: any): GateResult {
    return {
      gateId: this.id,
      gateName: this.name,
      status: 'PASS',
      findings: [],
      evidence
    };
  }

  /**
   * Helper to format a fail result.
   */
  protected fail(message: string, severity: any = 'HIGH', evidence?: any): GateResult {
    return {
      gateId: this.id,
      gateName: this.name,
      status: 'FAIL',
      findings: [{ severity, message }],
      evidence
    };
  }
}

import { BaseGate } from './BaseGate.js';
import { GateResult, CouncilEvidence } from './types.js';
import { execa } from 'execa';
import path from 'path';

export class CompatibilityGate extends BaseGate {
  get id() { return 'QG-010'; }
  get name() { return 'Backward Compatibility (Gate 10)'; }

  async run(evidence: CouncilEvidence): Promise<GateResult> {
    const modifiedFiles = this.getModifiedExistingFiles(evidence.gitDiff || '');
    const findings: any[] = [];

    if (modifiedFiles.length === 0) {
      return this.pass({ message: 'No existing files modified.' });
    }

    // Check for Vitest availability
    const hasVitest = await this.toolResolver.isAvailable('vitest');
    if (!hasVitest) {
      return this.fail('Vitest is not installed. Gate 10 requires an industry-standard test runner.', 'CRITICAL');
    }

    const resolvedVitest = this.toolResolver.resolve('vitest');

    for (const file of modifiedFiles) {
      const testFile = this.findTestForFile(file);
      
      if (!testFile) {
        findings.push({
          severity: 'HIGH',
          message: `File ${file} was modified but no test suite was found. Regression risk is high.`,
          file
        });
        continue;
      }

      try {
        // Run specific test for this file
        await execa(resolvedVitest, ['run', testFile], { cwd: this.cwd });
      } catch (error: any) {
        findings.push({
          severity: 'CRITICAL',
          message: `Regression detected in ${file}. Test suite ${testFile} failed.`,
          file
        });
      }
    }

    return {
      gateId: this.id,
      gateName: this.name,
      status: findings.length > 0 ? 'FAIL' : 'PASS',
      findings
    };
  }

  private getModifiedExistingFiles(diff: string): string[] {
    const lines = diff.split('\n');
    const files: string[] = [];
    
    // Simple diff parser for "--- a/path/to/file"
    for (const line of lines) {
      if (line.startsWith('--- a/')) {
        const filePath = line.replace('--- a/', '').trim();
        if (filePath !== '/dev/null') {
          files.push(filePath);
        }
      }
    }
    return files;
  }

  private findTestForFile(filePath: string): string | null {
    const basename = path.basename(filePath, path.extname(filePath));
    const dirname = path.dirname(filePath);
    
    // Heuristics for common test locations
    const candidates = [
      path.join(dirname, `${basename}.test.ts`),
      path.join(dirname, `${basename}.test.js`),
      path.join(dirname, '__tests__', `${basename}.test.ts`),
      path.join(this.cwd, 'tests', `${basename}.test.ts`),
      path.join(this.cwd, 'test', `${basename}.test.ts`)
    ];

    for (const c of candidates) {
      // Logic would be to check fs.existsSync here
      // For this implementation, we just return the first that exists
      if (require('fs').existsSync(path.resolve(this.cwd, c))) {
        return c;
      }
    }

    return null;
  }
}

import { BaseGate } from './BaseGate.js';
import { GateResult, CouncilEvidence } from './types.js';
import { execa } from 'execa';

export class StaticAnalysisGate extends BaseGate {
  get id() { return 'QG-002'; }
  get name() { return 'Static Analysis'; }

  async run(evidence: CouncilEvidence): Promise<GateResult> {
    const findings: any[] = [];
    
    // Check for ESLint
    if (await this.toolResolver.isAvailable('eslint')) {
      try {
        const resolved = this.toolResolver.resolve('eslint');
        await execa(resolved, ['.', '--ext', '.ts,.js'], { cwd: this.cwd });
      } catch (error: any) {
        findings.push({
          severity: 'HIGH',
          message: `Linting failed: ${error.stdout || error.message}`
        });
      }
    }

    // Check for Type Checking (TSC)
    if (await this.toolResolver.isAvailable('tsc')) {
      try {
        const resolved = this.toolResolver.resolve('tsc');
        await execa(resolved, ['--noEmit'], { cwd: this.cwd });
      } catch (error: any) {
        findings.push({
          severity: 'CRITICAL',
          message: `Type check failed: ${error.stdout || error.message}`
        });
      }
    }

    return {
      gateId: this.id,
      gateName: this.name,
      status: findings.length > 0 ? 'FAIL' : 'PASS',
      findings
    };
  }
}

export type GateSeverity = 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW';
export type GateStatus = 'PASS' | 'FAIL' | 'WARN' | 'SKIPPED';

export interface GateFinding {
  severity: GateSeverity;
  message: string;
  file?: string;
  line?: number;
}

export interface GateResult {
  gateId: string;
  gateName: string;
  status: GateStatus;
  findings: GateFinding[];
  evidence?: any;
}

export interface CouncilEvidence {
  prdPath?: string;
  gitDiff?: string;
  testLogs?: string[];
  buildLog?: string;
  iterationCount: number;
}

