  private pricing: Record<string, ModelPricing> = {
    // Platinum
    'claude-4.6-opus': { inputPer1M: 15, outputPer1M: 75 },
    'gpt-5.4-o': { inputPer1M: 10, outputPer1M: 30 },
    
    // Gold
    'claude-4.6-sonnet': { inputPer1M: 3, outputPer1M: 15 },
    'gemini-3.1-pro': { inputPer1M: 1.25, outputPer1M: 3.75 },
    
    // Silver (Efficiency)
    'claude-4.6-haiku': { inputPer1M: 0.25, outputPer1M: 1.25 },
    'gemini-1.5-flash': { inputPer1M: 0.075, outputPer1M: 0.3 },
    'gpt-4o-mini': { inputPer1M: 0.15, outputPer1M: 0.6 }
  };

  private statsDir: string;
  private sessionCost: number = 0;

  private constructor() {
    this.statsDir = path.join(process.cwd(), '.sognatore', 'stats');
    if (!fs.existsSync(this.statsDir)) {
      fs.mkdirSync(this.statsDir, { recursive: true });
    }
  }

  static getInstance(): CostTracker {
    if (!CostTracker.instance) {
      CostTracker.instance = new CostTracker();
    }
    return CostTracker.instance;
  }

  public calculateAndReport(model: string, inputTokens: number, outputTokens: number): number {
    const pricing = this.pricing[model] || this.pricing['claude-4.6-sonnet']; // Fallback
    const cost = (inputTokens / 1_000_000) * pricing.inputPer1M + 
                 (outputTokens / 1_000_000) * pricing.outputPer1M;

    this.sessionCost += cost;
    this.logTaskCost({
      model,
      inputTokens,
      outputTokens,
      cost,
      timestamp: new Date().toISOString()
    });

    console.log(
      chalk.cyan(`[💰 ECONOMÍA] `) + 
      chalk.white(`Tarea completada con `) + 
      chalk.yellow(model) + 
      chalk.white(` | Coste: `) + 
      chalk.green(`$${cost.toFixed(4)}`) + 
      chalk.white(` | Sesión: `) + 
      chalk.bold.green(`$${this.sessionCost.toFixed(4)}`)
    );

    return cost;
  }

  private logTaskCost(task: TaskCost) {
    const logFile = path.join(this.statsDir, 'usage_log.jsonl');
    fs.appendFileSync(logFile, JSON.stringify(task) + '\n');
    
    // Update global aggregated stats
    const globalStatsFile = path.join(this.statsDir, 'global_stats.json');
    let stats = { totalCost: 0, totalTasks: 0, models: {} as Record<string, number> };
    
    if (fs.existsSync(globalStatsFile)) {
      stats = JSON.parse(fs.readFileSync(globalStatsFile, 'utf8'));
    }

    stats.totalCost += task.cost;
    stats.totalTasks += 1;
    stats.models[task.model] = (stats.models[task.model] || 0) + 1;

    fs.writeFileSync(globalStatsFile, JSON.stringify(stats, null, 2));
  }

  public getSessionCost(): number {
    return this.sessionCost;
  }
}

import { execSync } from 'child_process';
import path from 'path';
import fs from 'fs-extra';
import chalk from 'chalk';

export class WindowsHookRunner {
  /**
   * Translates and executes a command that might contain Unix-isms.
   * This is a "compatibility layer" for the high-assurance system.
   */
  static run(command: string, cwd: string = process.cwd()): string {
    // 1. Basic path normalization
    let normalizedCommand = command.replace(/\//g, path.sep);

    // 2. Map common Unix-isms to PowerShell counterparts
    // 'touch' -> 'New-Item -ItemType File -Force'
    if (normalizedCommand.startsWith('touch ')) {
      const file = normalizedCommand.substring(6).trim();
      normalizedCommand = `New-Item -ItemType File -Force "${file}"`;
    }
    
    // 'rm -rf' -> 'Remove-Item -Recurse -Force'
    if (normalizedCommand.includes('rm -rf ')) {
      normalizedCommand = normalizedCommand.replace('rm -rf ', 'Remove-Item -Recurse -Force ');
    }

    try {
      console.log(chalk.dim(`  [HOOK] Executing: ${normalizedCommand}`));
      const output = execSync(normalizedCommand, { 
        cwd, 
        shell: 'powershell.exe',
        stdio: 'pipe' 
      });
      return output.toString();
    } catch (error: any) {
      console.error(chalk.red(`  [HOOK ERROR] Failed to execute hook: ${error.message}`));
      return '';
    }
  }

  /**
   * Triggers the "stagnation-hook" equivalent on Windows.
   */
  static triggerStagnationHook() {
    console.log(chalk.yellow(`\n[RECOVERY] Stagnation detected. Running recovery hooks...`));
    // In original: touch .sognatore/STAGNANT
    this.run('touch .sognatore/STAGNANT');
  }

  /**
   * Cleans up temporary agents and PIDs, mirroring the init_pid_registry logic.
   */
  static cleanupRegistry() {
    const pidDir = path.join(process.cwd(), '.sognatore', 'pids');
    if (fs.existsSync(pidDir)) {
      console.log(chalk.cyan(`[CLEANUP] Purging Windows PID registry...`));
      fs.emptyDirSync(pidDir);
    }
  }
}

'use strict';

const { EventEmitter } = require('events');

/**
 * Base integration adapter interface.
 * All external integrations (Linear, Jira, Slack, Teams) must extend this class.
 * Provides retry logic with exponential backoff and event emission for sync lifecycle.
 */
class IntegrationAdapter extends EventEmitter {
  /**
   * @param {string} name - Integration name (e.g., 'linear', 'jira')
   * @param {object} [options]
   * @param {number} [options.maxRetries=3] - Maximum retry attempts
   * @param {number} [options.baseDelay=1000] - Base delay in ms for exponential backoff
   * @param {number} [options.maxDelay=30000] - Maximum delay cap in ms
   */
  constructor(name, options = {}) {
    super();
    if (new.target === IntegrationAdapter) {
      throw new Error('IntegrationAdapter is abstract and cannot be instantiated directly');
    }
    this.name = name;
    this.maxRetries = options.maxRetries ?? 3;
    this.baseDelay = options.baseDelay ?? 1000;
    this.maxDelay = options.maxDelay ?? 30000;
  }

  /**
   * Import a project/issue from the external system and convert to PRD format.
   * @param {string} externalId - External system identifier
   * @returns {Promise<object>} PRD-formatted object
   */
  async importProject(externalId) {
    throw new Error(`${this.name}: importProject() not implemented`);
  }

  /**
   * Sync RARV status back to the external system.
   * @param {string} projectId - Internal project ID
   * @param {string} status - RARV status (REASON, ACT, REFLECT, VERIFY, DONE)
   * @param {object} [details] - Additional status details
   * @returns {Promise<object>} Sync result
   */
  async syncStatus(projectId, status, details) {
    throw new Error(`${this.name}: syncStatus() not implemented`);
  }

  /**
   * Post a comment to the external system (e.g., quality report).
   * @param {string} externalId - External system identifier
   * @param {string} content - Comment content (markdown)
   * @returns {Promise<object>} Comment result
   */
  async postComment(externalId, content) {
    throw new Error(`${this.name}: postComment() not implemented`);
  }

  /**
   * Create subtasks in the external system mirroring internal task decomposition.
   * @param {string} externalId - Parent external identifier
   * @param {Array<{title: string, description: string}>} tasks - Tasks to create
   * @returns {Promise<Array<object>>} Created subtask results
   */
  async createSubtasks(externalId, tasks) {
    throw new Error(`${this.name}: createSubtasks() not implemented`);
  }

  /**
   * Return an HTTP request handler for inbound webhook events.
   * The handler receives (req, res) and processes external system notifications.
   * @returns {function} HTTP request handler (req, res) => void
   */
  getWebhookHandler() {
    throw new Error(`${this.name}: getWebhookHandler() not implemented`);
  }

  /**
   * Execute an async function with exponential backoff retry.
   * Emits 'retry', 'success', and 'failure' events.
   * @param {string} operation - Operation name for logging
   * @param {function} fn - Async function to execute
   * @returns {Promise<*>} Result of fn
   */
  async withRetry(operation, fn) {
    let lastError;
    for (let attempt = 0; attempt <= this.maxRetries; attempt++) {
      try {
        const result = await fn();
        this.emit('success', { integration: this.name, operation, attempt });
        return result;
      } catch (err) {
        lastError = err;
        if (attempt < this.maxRetries) {
          const delay = Math.min(
            this.baseDelay * Math.pow(2, attempt),
            this.maxDelay
          );
          this.emit('retry', {
            integration: this.name,
            operation,
            attempt: attempt + 1,
            delay,
            error: err.message,
          });
          await this._sleep(delay);
        }
      }
    }
    this.emit('failure', {
      integration: this.name,
      operation,
      error: lastError.message,
      attempts: this.maxRetries + 1,
    });
    throw lastError;
  }

  /**
   * @param {number} ms
   * @returns {Promise<void>}
   */
  _sleep(ms) {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }
}

module.exports = { IntegrationAdapter };

'use strict';

/**
 * GitHub Actions Trigger Context Handler
 *
 * Parses GitHub webhook event payloads and extracts the relevant
 * context for Sognatore execution. Works both inside GitHub Actions
 * (with GITHUB_TOKEN) and standalone (with configured PAT).
 */

/**
 * Allowed provider values. The workflow_dispatch REST API can supply any
 * string even when the YAML declares a choice type, so we validate here.
 */
var ALLOWED_PROVIDERS = ['claude', 'codex', 'gemini'];

/**
 * Label-to-configuration mapping.
 * GitHub labels on issues/PRs can control Sognatore behavior.
 */
const LABEL_CONFIG_MAP = {
  'sognatore': { enabled: true },
  'sognatore-priority-high': { priority: 'high' },
  'sognatore-priority-low': { priority: 'low' },
  'sognatore-provider-codex': { provider: 'codex' },
  'sognatore-provider-gemini': { provider: 'gemini' },
  'sognatore-dry-run': { dryRun: true },
};

/**
 * Parse trigger context from a GitHub event.
 *
 * @param {Object} options
 * @param {string} options.eventName - GitHub event name (issues, pull_request_review, schedule, workflow_dispatch)
 * @param {Object} options.payload - GitHub event payload (parsed JSON)
 * @param {Object} [options.inputs] - workflow_dispatch inputs
 * @returns {Object} Structured trigger context for Sognatore
 */
function parseTriggerContext(options) {
  const { eventName, payload, inputs } = options;

  switch (eventName) {
    case 'issues':
      return parseIssueEvent(payload);
    case 'pull_request_review':
      return parsePullRequestReviewEvent(payload);
    case 'schedule':
      return parseScheduleEvent(payload);
    case 'workflow_dispatch':
      return parseWorkflowDispatchEvent(payload, inputs);
    default:
      return {
        triggerType: 'unknown',
        prd: '',
        provider: 'claude',
        dryRun: false,
        sourceId: null,
        sourceType: null,
        labels: [],
        metadata: { eventName },
      };
  }
}

/**
 * Parse an issue labeled event.
 * Extracts PRD content from the issue body.
 *
 * @param {Object} payload - GitHub issues event payload
 * @returns {Object} Trigger context
 */
function parseIssueEvent(payload) {
  const issue = payload.issue || {};
  const label = payload.label || {};
  const labels = (issue.labels || []).map(function (l) {
    return typeof l === 'string' ? l : l.name;
  });

  const config = mapLabelsToConfig(labels);

  return {
    triggerType: 'issue',
    prd: extractPrdFromBody(issue.body || ''),
    provider: config.provider || 'claude',
    dryRun: config.dryRun || false,
    sourceId: String(issue.number || ''),
    sourceType: 'issue',
    labels: labels,
    metadata: {
      issueNumber: issue.number,
      issueTitle: issue.title || '',
      issueUrl: issue.html_url || '',
      triggerLabel: label.name || '',
      author: (issue.user || {}).login || '',
      repository: (payload.repository || {}).full_name || '',
    },
  };
}

/**
 * Parse a pull_request_review event.
 * Extracts context from the PR description.
 *
 * @param {Object} payload - GitHub pull_request_review event payload
 * @returns {Object} Trigger context
 */
function parsePullRequestReviewEvent(payload) {
  const pr = payload.pull_request || {};
  const review = payload.review || {};
  const labels = (pr.labels || []).map(function (l) {
    return typeof l === 'string' ? l : l.name;
  });

  const config = mapLabelsToConfig(labels);

  return {
    triggerType: 'pull_request_review',
    prd: extractPrdFromBody(pr.body || ''),
    provider: config.provider || 'claude',
    dryRun: config.dryRun || false,
    sourceId: String(pr.number || ''),
    sourceType: 'pull_request',
    labels: labels,
    metadata: {
      prNumber: pr.number,
      prTitle: pr.title || '',
      prUrl: pr.html_url || '',
      prHead: (pr.head || {}).ref || '',
      prBase: (pr.base || {}).ref || '',
      reviewState: review.state || '',
      reviewAuthor: (review.user || {}).login || '',
      author: (pr.user || {}).login || '',
      repository: (payload.repository || {}).full_name || '',
    },
  };
}

/**
 * Parse a schedule event.
 *
 * @param {Object} payload - GitHub schedule event payload
 * @returns {Object} Trigger context
 */
function parseScheduleEvent(payload) {
  return {
    triggerType: 'schedule',
    prd: '',
    provider: 'claude',
    dryRun: false,
    sourceId: null,
    sourceType: null,
    labels: [],
    metadata: {
      schedule: (payload || {}).schedule || '',
      repository: (payload.repository || {}).full_name || '',
    },
  };
}

/**
 * Parse a workflow_dispatch event.
 *
 * @param {Object} payload - GitHub workflow_dispatch event payload
 * @param {Object} inputs - Workflow dispatch inputs
 * @returns {Object} Trigger context
 */
function parseWorkflowDispatchEvent(payload, inputs) {
  const prdContent = (inputs || {}).prd_content || '';
  // Validate provider against the allowed set to prevent shell metacharacter injection.
  // The GitHub UI enforces the choice constraint but the REST API does not.
  var rawProvider = (inputs || {}).provider || 'claude';
  var provider = ALLOWED_PROVIDERS.indexOf(rawProvider) !== -1 ? rawProvider : 'claude';
  const dryRun = (inputs || {}).dry_run === true || (inputs || {}).dry_run === 'true';

  return {
    triggerType: 'workflow_dispatch',
    prd: prdContent,
    provider: provider,
    dryRun: dryRun,
    sourceId: null,
    sourceType: null,
    labels: [],
    metadata: {
      sender: ((payload || {}).sender || {}).login || '',
      repository: ((payload || {}).repository || {}).full_name || '',
    },
  };
}

/**
 * Extract PRD content from an issue or PR body.
 * Looks for content between PRD markers, or uses the full body
 * if no markers are found.
 *
 * Supported markers:
 *   <!-- PRD_START --> ... <!-- PRD_END -->
 *   ```prd ... ```
 *   ## PRD ... (until next ## heading or end)
 *
 * @param {string} body - Issue or PR body text
 * @returns {string} Extracted PRD content
 */
function extractPrdFromBody(body) {
  if (!body || typeof body !== 'string') {
    return '';
  }

  // Try HTML comment markers first
  var commentMatch = body.match(/<!--\s*PRD_START\s*-->([\s\S]*?)<!--\s*PRD_END\s*-->/i);
  if (commentMatch) {
    return commentMatch[1].trim();
  }

  // Try fenced code block with prd language
  var codeMatch = body.match(/```prd\s*\n([\s\S]*?)```/i);
  if (codeMatch) {
    return codeMatch[1].trim();
  }

  // Try PRD section header.
  // Do NOT use the /m flag here: with /m, the $ anchor matches end-of-line instead
  // of end-of-string, causing the regex to stop at the first blank line inside the
  // section rather than at the next ## heading or the real end of the document.
  var sectionMatch = body.match(/(?:^|\n)##\s+PRD\s*\n([\s\S]*?)(?=\n##\s|\s*$)/i);
  if (sectionMatch) {
    return sectionMatch[1].trim();
  }

  // Fall back to the full body
  return body.trim();
}

/**
 * Map GitHub labels to Sognatore configuration options.
 *
 * @param {string[]} labels - Array of label names
 * @returns {Object} Merged configuration from matching labels
 */
function mapLabelsToConfig(labels) {
  var config = {};
  if (!Array.isArray(labels)) {
    return config;
  }

  labels.forEach(function (label) {
    var mapping = LABEL_CONFIG_MAP[label];
    if (mapping) {
      Object.keys(mapping).forEach(function (key) {
        config[key] = mapping[key];
      });
    }
  });

  return config;
}

module.exports = {
  parseTriggerContext: parseTriggerContext,
  parseIssueEvent: parseIssueEvent,
  parsePullRequestReviewEvent: parsePullRequestReviewEvent,
  parseScheduleEvent: parseScheduleEvent,
  parseWorkflowDispatchEvent: parseWorkflowDispatchEvent,
  extractPrdFromBody: extractPrdFromBody,
  mapLabelsToConfig: mapLabelsToConfig,
  LABEL_CONFIG_MAP: LABEL_CONFIG_MAP,
  ALLOWED_PROVIDERS: ALLOWED_PROVIDERS,
};

'use strict';

/**
 * GitHub Results Reporter
 *
 * Posts Sognatore execution results back to GitHub as PR comments,
 * issue comments, and status checks. Works both inside GitHub Actions
 * (with GITHUB_TOKEN) and standalone (with configured PAT).
 *
 * Uses only Node.js built-in https module for GitHub REST API calls.
 */

var https = require('https');
var fs = require('fs');
var path = require('path');

/**
 * Post execution results to GitHub based on the trigger event type.
 *
 * @param {Object} options
 * @param {string} options.eventName - GitHub event name
 * @param {Object} options.payload - GitHub event payload
 * @param {string} options.status - Execution status (success, failure, unknown)
 * @param {string} options.executionId - Unique execution identifier
 * @param {string} options.repository - Repository full name (owner/repo)
 * @param {string} options.sha - Commit SHA for status checks
 * @param {string} options.serverUrl - GitHub server URL
 * @param {string} options.runId - GitHub Actions run ID
 * @param {string} options.token - GitHub token (GITHUB_TOKEN or PAT)
 * @param {string} [options.reportsPath] - Path to .sognatore/reports directory
 */
async function postResults(options) {
  var eventName = options.eventName;
  var payload = options.payload;
  var token = options.token;

  if (!token) {
    throw new Error('GitHub token is required. Set GITHUB_TOKEN or provide a PAT.');
  }

  var report = loadReport(options.reportsPath);

  switch (eventName) {
    case 'pull_request_review':
      await postPrComment(options, report);
      await createStatusCheck(options, report);
      break;
    case 'issues':
      await postIssueComment(options, report);
      break;
    case 'workflow_dispatch':
    case 'schedule':
      // For manual and scheduled triggers, create a status check on the SHA
      await createStatusCheck(options, report);
      break;
    default:
      console.log('No reporting action for event:', eventName);
  }
}

/**
 * Post a quality report comment on a pull request.
 *
 * @param {Object} options - Same as postResults options
 * @param {Object} report - Parsed report data
 */
async function postPrComment(options, report) {
  var pr = (options.payload || {}).pull_request || {};
  var prNumber = pr.number;

  if (!prNumber) {
    console.log('No PR number found in payload, skipping PR comment.');
    return;
  }

  var body = renderQualityReport(report, options);
  var parts = options.repository.split('/');
  var owner = parts[0];
  var repo = parts[1];

  await githubApiRequest({
    method: 'POST',
    path: '/repos/' + owner + '/' + repo + '/issues/' + prNumber + '/comments',
    token: options.token,
    body: { body: body },
  });

  console.log('Posted quality report to PR #' + prNumber);
}

/**
 * Post an execution summary comment on an issue.
 *
 * @param {Object} options - Same as postResults options
 * @param {Object} report - Parsed report data
 */
async function postIssueComment(options, report) {
  var issue = (options.payload || {}).issue || {};
  var issueNumber = issue.number;

  if (!issueNumber) {
    console.log('No issue number found in payload, skipping issue comment.');
    return;
  }

  var body = renderExecutionSummary(report, options);
  var parts = options.repository.split('/');
  var owner = parts[0];
  var repo = parts[1];

  await githubApiRequest({
    method: 'POST',
    path: '/repos/' + owner + '/' + repo + '/issues/' + issueNumber + '/comments',
    token: options.token,
    body: { body: body },
  });

  console.log('Posted execution summary to issue #' + issueNumber);
}

/**
 * Create a GitHub commit status check.
 *
 * @param {Object} options - Same as postResults options
 * @param {Object} report - Parsed report data
 */
async function createStatusCheck(options, report) {
  var sha = options.sha;
  if (!sha) {
    console.log('No SHA available, skipping status check.');
    return;
  }

  var parts = options.repository.split('/');
  var owner = parts[0];
  var repo = parts[1];

  var state = options.status === 'success' ? 'success' : 'failure';
  var description = options.status === 'success'
    ? 'Sognatore execution completed successfully'
    : 'Sognatore execution completed with errors';

  var targetUrl = options.serverUrl + '/' + options.repository + '/actions/runs/' + options.runId;

  await githubApiRequest({
    method: 'POST',
    path: '/repos/' + owner + '/' + repo + '/statuses/' + sha,
    token: options.token,
    body: {
      state: state,
      target_url: targetUrl,
      description: description,
      context: 'sognatore/enterprise',
    },
  });

  console.log('Created status check on commit ' + sha.substring(0, 7) + ': ' + state);
}

/**
 * Load execution report from the reports directory.
 *
 * @param {string} [reportsPath] - Path to .sognatore/reports
 * @returns {Object} Parsed report data with defaults
 */
function loadReport(reportsPath) {
  var report = {
    qualityGates: [],
    tasksCompleted: 0,
    tasksFailed: 0,
    totalTasks: 0,
    duration: 'unknown',
    deploymentUrl: null,
    summary: 'No detailed report available.',
  };

  if (!reportsPath) {
    return report;
  }

  // Try to load quality gate results
  var qualityPath = path.join(reportsPath, 'quality-gates.json');
  if (fs.existsSync(qualityPath)) {
    try {
      var qualityData = JSON.parse(fs.readFileSync(qualityPath, 'utf8'));
      report.qualityGates = qualityData.gates || qualityData || [];
    } catch (e) {
      console.log('Warning: Could not parse quality-gates.json:', e.message);
    }
  }

  // Try to load execution summary
  var summaryPath = path.join(reportsPath, 'summary.json');
  if (fs.existsSync(summaryPath)) {
    try {
      var summaryData = JSON.parse(fs.readFileSync(summaryPath, 'utf8'));
      report.tasksCompleted = summaryData.tasksCompleted || 0;
      report.tasksFailed = summaryData.tasksFailed || 0;
      report.totalTasks = summaryData.totalTasks || 0;
      report.duration = summaryData.duration || 'unknown';
      report.deploymentUrl = summaryData.deploymentUrl || null;
      report.summary = summaryData.summary || report.summary;
    } catch (e) {
      console.log('Warning: Could not parse summary.json:', e.message);
    }
  }

  return report;
}

/**
 * Render quality report markdown for PR comments.
 *
 * @param {Object} report - Parsed report data
 * @param {Object} options - Execution options
 * @returns {string} Formatted markdown
 */
function renderQualityReport(report, options) {
  var templatePath = path.join(__dirname, 'templates', 'quality-report.md');
  var template = '';

  if (fs.existsSync(templatePath)) {
    template = fs.readFileSync(templatePath, 'utf8');
  } else {
    template = getDefaultQualityReportTemplate();
  }

  return applyTemplate(template, report, options);
}

/**
 * Render execution summary markdown for issue comments.
 *
 * @param {Object} report - Parsed report data
 * @param {Object} options - Execution options
 * @returns {string} Formatted markdown
 */
function renderExecutionSummary(report, options) {
  var templatePath = path.join(__dirname, 'templates', 'execution-summary.md');
  var template = '';

  if (fs.existsSync(templatePath)) {
    template = fs.readFileSync(templatePath, 'utf8');
  } else {
    template = getDefaultExecutionSummaryTemplate();
  }

  return applyTemplate(template, report, options);
}

/**
 * Escape a string value before inserting it into a markdown context.
 * Strips characters that can break markdown structure in inline positions:
 * backticks, square brackets, parentheses, and bare newlines in
 * single-line fields. For multi-line fields (summary, gates details)
 * only bracket/paren pairs that could create unintended links are escaped.
 *
 * @param {string} value - Raw user-controlled string
 * @param {boolean} [multiline] - Allow newlines (default false)
 * @returns {string} Escaped string safe for markdown inline use
 */
function escapeMarkdown(value, multiline) {
  if (typeof value !== 'string') {
    return String(value);
  }
  // Replace characters that have structural meaning in markdown
  var escaped = value
    .replace(/\\/g, '\\\\')
    .replace(/`/g, '\\`')
    .replace(/\[/g, '\\[')
    .replace(/\]/g, '\\]')
    .replace(/\(/g, '\\(')
    .replace(/\)/g, '\\)');
  if (!multiline) {
    // Collapse newlines to a space for single-line fields
    escaped = escaped.replace(/[\r\n]+/g, ' ');
  }
  return escaped;
}

/**
 * Validate a URL is safe to use as a markdown link target.
 * Only https:// URLs are allowed to prevent javascript: and data: injection.
 *
 * @param {string} url - URL to validate
 * @returns {boolean}
