/**
 * Extract plain text from Jira ADF or plain string.
 */
function _extractDescription(desc) {
  if (!desc) return '';
  if (typeof desc === 'string') return desc;
  // ADF (Atlassian Document Format)
  if (desc.type === 'doc' && Array.isArray(desc.content)) {
