        },
        {
            type: 'section',
            text: {
                type: 'mrkdwn',
                text: '*Project:* ' + (projectId || 'Unknown') + '\n*Error:* ' + (error || 'Unknown error')
            }
        }
    ];
}

module.exports = { buildStatusBlocks, buildApprovalBlocks, buildErrorBlocks };

