    this._labeledValues = {};
  }

  add(value, labels) {
    if (value < 0) return; // counters are monotonic
    if (labels) {
      const key = JSON.stringify(labels);
      if (!(key in this._labeledValues)) {
        if (Object.keys(this._labeledValues).length >= MAX_METRIC_CARDINALITY) {
          // Refuse new label sets to preserve monotonicity of existing counters.
          // Eviction would destroy accumulated counts and violate the monotonic invariant.
          process.stderr.write(
            `[sognatore-otel] Counter "${this.name}" cardinality limit reached; dropping new label set: ${key}\n`
          );
          return;
        }
        this._labeledValues[key] = 0;
      }
      this._labeledValues[key] += value;
    } else {
      this._value += value;
    }
  }

  get(labels) {
    if (labels) {
      const key = JSON.stringify(labels);
      return this._labeledValues[key] || 0;
    }
    return this._value;
  }

  toOTLP() {
    const dataPoints = [];

    // Only emit the unlabeled data point if it has been incremented,
    // or if there are no labeled values (always need at least one point).
    if (this._value !== 0 || Object.keys(this._labeledValues).length === 0) {
      dataPoints.push({
        attributes: [],
        asInt: String(this._value),
        timeUnixNano: nowNanos(),
      });
    }

    // Include all labeled data points
    for (const [key, value] of Object.entries(this._labeledValues)) {
      const labels = JSON.parse(key);
      const attrs = Object.entries(labels).map(([k, v]) => ({
        key: k,
        value: { stringValue: String(v) },
      }));
      dataPoints.push({
        attributes: attrs,
        asInt: String(value),
        timeUnixNano: nowNanos(),
      });
    }

    return {
      name: this.name,
      description: this.description,
      unit: this.unit,
      sum: {
        dataPoints,
        aggregationTemporality: 2, // CUMULATIVE
        isMonotonic: true,
      },
    };
  }
}

class Gauge {
  constructor(name, description, unit) {
    this.name = name;
    this.description = description || '';
    this.unit = unit || '';
    this._value = 0;
    this._labeledValues = {};
  }

  set(value, labels) {
    if (labels) {
      const key = JSON.stringify(labels);
      if (!(key in this._labeledValues) && Object.keys(this._labeledValues).length >= MAX_METRIC_CARDINALITY) {
        const firstKey = Object.keys(this._labeledValues)[0];
        delete this._labeledValues[firstKey];
      }
      this._labeledValues[key] = value;
    } else {
      this._value = value;
    }
  }

  get(labels) {
    if (labels) {
      const key = JSON.stringify(labels);
      return this._labeledValues[key] || 0;
    }
    return this._value;
  }

  toOTLP() {
    const dataPoints = [];

    // Only emit the unlabeled data point if it has been set to a non-zero value,
    // or if there are no labeled values (always need at least one point).
    if (this._value !== 0 || Object.keys(this._labeledValues).length === 0) {
      dataPoints.push({
        attributes: [],
        asDouble: this._value,
        timeUnixNano: nowNanos(),
      });
    }

    // Include all labeled data points
    for (const [key, value] of Object.entries(this._labeledValues)) {
      const labels = JSON.parse(key);
      const attrs = Object.entries(labels).map(([k, v]) => ({
        key: k,
        value: { stringValue: String(v) },
      }));
      dataPoints.push({
        attributes: attrs,
        asDouble: value,
        timeUnixNano: nowNanos(),
      });
    }

    return {
      name: this.name,
      description: this.description,
      unit: this.unit,
      gauge: { dataPoints },
    };
  }
}

class Histogram {
  constructor(name, description, unit, boundaries) {
    this.name = name;
    this.description = description || '';
    this.unit = unit || '';
    this.boundaries = boundaries || [0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5, 10];
    this._values = [];
    this._labeledValues = {};
  }

  record(value, labels) {
    if (labels) {
      const key = JSON.stringify(labels);
      if (!(key in this._labeledValues)) {
        if (Object.keys(this._labeledValues).length >= MAX_METRIC_CARDINALITY) {
          // Refuse new label sets rather than evicting existing series.
          // Eviction would lose all accumulated histogram data for that series.
          process.stderr.write(
            `[sognatore-otel] Histogram "${this.name}" cardinality limit reached; dropping new label set: ${key}\n`
          );
          return;
        }
        this._labeledValues[key] = [];
      }
      if (this._labeledValues[key].length < MAX_HISTOGRAM_SAMPLES) {
        this._labeledValues[key].push(value);
      }
      // Silently drop samples beyond the cap to bound memory usage.
    } else {
      if (this._values.length < MAX_HISTOGRAM_SAMPLES) {
        this._values.push(value);
      }
      // Silently drop samples beyond the cap to bound memory usage.
    }
  }

  get(labels) {
    if (labels) {
      const key = JSON.stringify(labels);
      return this._labeledValues[key] || [];
    }
    return this._values;
  }

  _computeBucketCounts(values) {
    const counts = new Array(this.boundaries.length + 1).fill(0);
    for (const v of values) {
      let placed = false;
      for (let i = 0; i < this.boundaries.length; i++) {
        if (v <= this.boundaries[i]) {
          counts[i]++;
          placed = true;
          break;
        }
      }
      if (!placed) {
        counts[this.boundaries.length]++;
      }
    }
    return counts;
  }

  toOTLP() {
    const dataPoints = [];

    const makePoint = (values, attrs) => {
      const bucketCounts = this._computeBucketCounts(values);
      const sum = values.reduce((a, b) => a + b, 0);
      return {
        attributes: attrs || [],
        count: String(values.length),
        sum: sum,
        bucketCounts: bucketCounts.map(String),
        explicitBounds: this.boundaries,
        timeUnixNano: nowNanos(),
      };
    };

    if (Object.keys(this._labeledValues).length > 0) {
      for (const [key, values] of Object.entries(this._labeledValues)) {
        const labels = JSON.parse(key);
        const attrs = Object.entries(labels).map(([k, v]) => ({
          key: k,
          value: { stringValue: String(v) },
        }));
        dataPoints.push(makePoint(values, attrs));
      }
    } else if (this._values.length > 0) {
      dataPoints.push(makePoint(this._values));
    }

    return {
      name: this.name,
      description: this.description,
      unit: this.unit,
      histogram: {
        dataPoints,
        aggregationTemporality: 2, // CUMULATIVE
      },
    };
  }
}

// -------------------------------------------------------------------
// OTLP HTTP/JSON Exporter (uses Node.js built-in http/https)
// -------------------------------------------------------------------

let _activeExporter = null;

class OTLPExporter {
  constructor(endpoint) {
    // SSRF protection: only allow http: and https: schemes
    const parsedUrl = new URL(endpoint);
    if (parsedUrl.protocol !== 'http:' && parsedUrl.protocol !== 'https:') {
      throw new Error(
        `Invalid OTEL endpoint scheme "${parsedUrl.protocol}". Only http: and https: are allowed.`
      );
    }
    this._endpoint = endpoint.replace(/\/$/, '');
    this._pendingSpans = [];
    this._flushTimer = null;
    this._flushIntervalMs = 5000;
    this._serviceName = process.env.SOGNATORE_SERVICE_NAME || 'sognatore';
    this._errorHandler = OTLPExporter._defaultErrorHandler;
    this._startFlushTimer();
  }

  static _defaultErrorHandler(err) {
    process.stderr.write(`[sognatore-otel] export error: ${err.message || err.code || String(err)}\n`);
  }

  /**
   * Set a custom error handler for export failures.
   * @param {Function} handler - function(err) called on network errors
   */
  setErrorHandler(handler) {
    this._errorHandler = handler || OTLPExporter._defaultErrorHandler;
  }

  addSpan(span) {
    this._pendingSpans.push(span);
    // Auto-flush if batch is large
    if (this._pendingSpans.length >= 100) {
      this.flush();
    }
  }

  _startFlushTimer() {
    this._flushTimer = setInterval(() => {
      if (this._pendingSpans.length > 0) {
        this.flush();
      }
    }, this._flushIntervalMs);
    // Allow the process to exit even if the timer is running
    if (this._flushTimer.unref) {
      this._flushTimer.unref();
    }
  }

  flush() {
    if (this._pendingSpans.length === 0) return;

    const spans = this._pendingSpans.splice(0);
    const payload = {
      resourceSpans: [
        {
          resource: {
            attributes: [
              {
                key: 'service.name',
                value: { stringValue: this._serviceName },
              },
            ],
          },
          scopeSpans: [
            {
              scope: { name: 'sognatore-otel', version: _scopeVersion },
              spans: spans.map((s) => s.toOTLP()),
            },
          ],
        },
      ],
    };

    this._send('/v1/traces', payload);
    return payload;
  }

  flushMetrics(metricsList) {
    if (!metricsList || metricsList.length === 0) return;

    const metrics = metricsList.map((m) => m.toOTLP());

    // Reset histogram sample arrays after export so they don't grow unboundedly
    // between flush cycles. Bucket counts are recomputed from the fresh arrays
    // on the next flush.
    for (const m of metricsList) {
      if (m instanceof Histogram) {
        m._values = [];
        for (const key of Object.keys(m._labeledValues)) {
          m._labeledValues[key] = [];
        }
      }
    }

    const payload = {
      resourceMetrics: [
        {
          resource: {
            attributes: [
              {
                key: 'service.name',
                value: { stringValue: this._serviceName },
              },
            ],
          },
          scopeMetrics: [
            {
              scope: { name: 'sognatore-otel', version: _scopeVersion },
              metrics,
            },
          ],
        },
      ],
    };

    this._send('/v1/metrics', payload);
    return payload;
  }

  _send(path, payload) {
    const url = new URL(this._endpoint + path);
    const isHttps = url.protocol === 'https:';
    const httpModule = isHttps ? require('https') : require('http');

    const body = JSON.stringify(payload);
    const options = {
      hostname: url.hostname,
      port: url.port || (isHttps ? 443 : 80),
      path: url.pathname,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body),
      },
    };

    const req = httpModule.request(options, (res) => {
      // Consume response to free socket
      res.resume();
    });

    req.on('error', (err) => {
      // Log but never throw - observability should never break the application
      try {
        this._errorHandler(err);
      } catch (_) {
        // Error handler itself failed; swallow to protect the app
      }
    });

    req.write(body);
    req.end();
  }

  shutdown() {
    if (this._flushTimer) {
      clearInterval(this._flushTimer);
      this._flushTimer = null;
    }
    this.flush();
  }
}

// -------------------------------------------------------------------
// Initialization
// -------------------------------------------------------------------

let _initialized = false;
let _tracerProvider = null;
let _meterProvider = null;
let _realSDKProvider = null;
let _usingRealSDK = false;

function initialize() {
  if (_initialized) return;

  const endpoint = process.env.SOGNATORE_OTEL_ENDPOINT;
  if (!endpoint) {
    throw new Error('SOGNATORE_OTEL_ENDPOINT is not set. Use index.js for conditional loading.');
  }

  // Try real OpenTelemetry SDK first, fall back to custom OTLP exporter
  let usingRealSDK = false;
  try {
    const { NodeTracerProvider } = require('@opentelemetry/sdk-trace-node');
    const { OTLPTraceExporter } = require('@opentelemetry/exporter-trace-otlp-http');
    const { SimpleSpanProcessor } = require('@opentelemetry/sdk-trace-base');
    const api = require('@opentelemetry/api');

    const exporter = new OTLPTraceExporter({ url: endpoint + '/v1/traces' });
    const provider = new NodeTracerProvider();
    provider.addSpanProcessor(new SimpleSpanProcessor(exporter));
    provider.register();

    _tracerProvider = {
      getTracer: (name) => api.trace.getTracer(name),
    };
    _meterProvider = {
      getMeter: (name) => ({
        createCounter: (n, desc, unit) => new Counter(n, desc, unit),
        createGauge: (n, desc, unit) => new Gauge(n, desc, unit),
        createHistogram: (n, desc, unit, boundaries) => new Histogram(n, desc, unit, boundaries),
      }),
    };
    _realSDKProvider = provider;
    usingRealSDK = true;
  } catch (_sdkErr) {
    // Real SDK not available -- fall back to custom OTLP exporter
    _activeExporter = new OTLPExporter(endpoint);
    _tracerProvider = {
      getTracer: (name) => ({
        startSpan: (spanName, options) => {
          const opts = options || {};
          return new Span(
            spanName,
            opts.traceId,
            opts.parentSpanId,
            opts.attributes
          );
        },
      }),
    };

    _meterProvider = {
      getMeter: (name) => ({
        createCounter: (n, desc, unit) => new Counter(n, desc, unit),
        createGauge: (n, desc, unit) => new Gauge(n, desc, unit),
        createHistogram: (n, desc, unit, boundaries) => new Histogram(n, desc, unit, boundaries),
      }),
    };
  }

  _initialized = true;
  _usingRealSDK = usingRealSDK;
}

function shutdown() {
  if (_realSDKProvider) {
    try { _realSDKProvider.shutdown(); } catch (_e) { /* ignore */ }
    _realSDKProvider = null;
  }
  if (_activeExporter) {
    _activeExporter.shutdown();
  }
  _activeExporter = null;
  _initialized = false;
  _usingRealSDK = false;
  _tracerProvider = null;
  _meterProvider = null;
}

function isUsingRealSDK() {
  return _usingRealSDK;
}

function isInitialized() {
  return _initialized;
}

function getExporter() {
  return _activeExporter;
}

module.exports = {
  initialize,
  shutdown,
  isInitialized,
  isUsingRealSDK,
  getExporter,
  get tracerProvider() {
    return _tracerProvider;
  },
  get meterProvider() {
    return _meterProvider;
  },
  // Exported for testing and direct use
  Span,
  Counter,
  Gauge,
  Histogram,
  SpanStatusCode,
  OTLPExporter,
  generateTraceId,
  generateSpanId,
  nowNanos,
  MAX_METRIC_CARDINALITY,
  MAX_HISTOGRAM_SAMPLES,
};

'use strict';

/**
 * Span creation helpers for Sognatore instrumentation.
 *
 * Provides typed span constructors for the RARV cycle, quality gates,
 * agent lifecycle, and completion council.
 *
 * All span functions accept an optional parentSpan to build trace hierarchies.
 * When a parentSpan is provided, the child span inherits the traceId and
 * references the parent's spanId.
 */

const otel = require('./otel');

// -------------------------------------------------------------------
// Helper: create a child span from a parent
// -------------------------------------------------------------------

function _createSpan(name, parentSpan, attributes) {
  // Always use our custom Span class for consistent interface.
  // The real OTEL SDK tracer (when available) returns span objects with
  // a different API (spanContext(), etc.) that breaks our attribute access.
  return new otel.Span(
    name,
    parentSpan ? parentSpan.traceId : undefined,
    parentSpan ? parentSpan.spanId : undefined,
    attributes || {}
  );
}

// -------------------------------------------------------------------
// Project span - root span for an entire project execution
// -------------------------------------------------------------------

/**
 * Start a root span for a project.
 * @param {string} projectId - The project identifier
 * @returns {Span} The root project span
 */
function startProjectSpan(projectId) {
  const span = _createSpan('project', null, {
    'sognatore.project.id': projectId,
    'sognatore.span.type': 'project',
  });
  return span;
}

// -------------------------------------------------------------------
// Task span - child of a project span
// -------------------------------------------------------------------

/**
 * Start a span for an individual task within a project.
 * @param {Span} parentSpan - The parent project span
 * @param {string} taskId - The task identifier
 * @returns {Span} The task span
 */
function startTaskSpan(parentSpan, taskId) {
  const span = _createSpan('task', parentSpan, {
    'sognatore.task.id': taskId,
    'sognatore.span.type': 'task',
  });
  return span;
}

// -------------------------------------------------------------------
// RARV cycle span - child of a task span
// -------------------------------------------------------------------

const VALID_RARV_PHASES = ['REASON', 'ACT', 'REFLECT', 'VERIFY'];

/**
 * Start a span for a RARV cycle phase.
 * @param {Span} parentSpan - The parent task span
 * @param {string} phase - One of: REASON, ACT, REFLECT, VERIFY
 * @returns {Span} The RARV phase span
 */
function startRARVSpan(parentSpan, phase) {
  const normalizedPhase = (phase || '').toUpperCase();
  if (!VALID_RARV_PHASES.includes(normalizedPhase)) {
    throw new Error(
      `Invalid RARV phase: "${phase}". Must be one of: ${VALID_RARV_PHASES.join(', ')}`
    );
  }

  const span = _createSpan(`rarv.${normalizedPhase.toLowerCase()}`, parentSpan, {
    'sognatore.rarv.phase': normalizedPhase,
    'sognatore.span.type': 'rarv',
  });
  return span;
}

// -------------------------------------------------------------------
// Quality gate span - child of a task or RARV span
// -------------------------------------------------------------------

/**
 * Start a span for a quality gate check.
 * @param {Span} parentSpan - The parent span
 * @param {string} gateName - Name of the quality gate
 * @param {string} result - 'pass' or 'fail'
 * @returns {Span} The quality gate span
 */
function startQualityGateSpan(parentSpan, gateName, result) {
  const normalizedResult = (result || '').toLowerCase();
  const passed = normalizedResult === 'pass';

  const span = _createSpan(`quality_gate.${gateName}`, parentSpan, {
    'sognatore.quality_gate.name': gateName,
    'sognatore.quality_gate.result': normalizedResult,
    'sognatore.quality_gate.passed': passed,
    'sognatore.span.type': 'quality_gate',
  });

  if (!passed) {
    span.setStatus(otel.SpanStatusCode.ERROR, `Quality gate "${gateName}" failed`);
  } else {
    span.setStatus(otel.SpanStatusCode.OK);
  }

  return span;
}

// -------------------------------------------------------------------
// Agent lifecycle span - child of a task span
// -------------------------------------------------------------------

const VALID_AGENT_ACTIONS = ['spawn', 'work', 'complete', 'fail'];

/**
 * Start a span for an agent lifecycle event.
 * @param {Span} parentSpan - The parent span
 * @param {string} agentType - Type of agent (e.g., 'code-review', 'test-writer')
 * @param {string} action - One of: spawn, work, complete, fail
 * @returns {Span} The agent span
 */
function startAgentSpan(parentSpan, agentType, action) {
  const normalizedAction = (action || '').toLowerCase();
  if (!VALID_AGENT_ACTIONS.includes(normalizedAction)) {
    throw new Error(
      `Invalid agent action: "${action}". Must be one of: ${VALID_AGENT_ACTIONS.join(', ')}`
    );
  }

  const span = _createSpan(`agent.${agentType}.${normalizedAction}`, parentSpan, {
    'sognatore.agent.type': agentType,
    'sognatore.agent.action': normalizedAction,
    'sognatore.span.type': 'agent',
  });

  if (normalizedAction === 'fail') {
    span.setStatus(otel.SpanStatusCode.ERROR, `Agent "${agentType}" failed`);
  }

  return span;
}

// -------------------------------------------------------------------
// Council review span - child of a task span
// -------------------------------------------------------------------

/**
 * Start a span for a completion council review.
 * @param {Span} parentSpan - The parent span
 * @param {string} reviewerType - Type of reviewer (e.g., 'security', 'performance')
 * @param {string} verdict - The review verdict (e.g., 'approve', 'reject', 'request-changes')
 * @returns {Span} The council span
 */
function startCouncilSpan(parentSpan, reviewerType, verdict) {
  const normalizedVerdict = (verdict || '').toLowerCase();
  const approved = normalizedVerdict === 'approve';

  const span = _createSpan(`council.${reviewerType}`, parentSpan, {
    'sognatore.council.reviewer': reviewerType,
    'sognatore.council.verdict': normalizedVerdict,
    'sognatore.council.approved': approved,
    'sognatore.span.type': 'council',
  });

  if (normalizedVerdict === 'reject') {
    span.setStatus(otel.SpanStatusCode.ERROR, `Council reviewer "${reviewerType}" rejected`);
  } else if (approved) {
    span.setStatus(otel.SpanStatusCode.OK);
  }

  return span;
}

module.exports = {
  startProjectSpan,
  startTaskSpan,
  startRARVSpan,
  startQualityGateSpan,
  startAgentSpan,
  startCouncilSpan,
  VALID_RARV_PHASES,
  VALID_AGENT_ACTIONS,
};

'use strict';

const { BUILTIN_AGENT_NAMES } = require('./validator');

// In-memory registry for custom agent plugins
const _registeredAgents = new Map();

class AgentPlugin {
    /**
     * Register a custom agent plugin.
     * Cannot override built-in agent types (additive only).
     *
     * @param {object} pluginConfig - Validated agent plugin config
     * @param {object} [registry] - Optional external registry to also register into
     * @returns {{ success: boolean, error?: string }}
     */
    static register(pluginConfig, registry) {
        if (!pluginConfig || pluginConfig.type !== 'agent') {
            return { success: false, error: 'Invalid plugin config: type must be "agent"' };
        }

        const name = pluginConfig.name;

        // Prevent overriding built-in agents
        if (BUILTIN_AGENT_NAMES.includes(name)) {
            return {
                success: false,
                error: `Cannot override built-in agent type: "${name}"`,
            };
        }

        // Check for duplicate custom registration
        if (_registeredAgents.has(name)) {
            return {
                success: false,
                error: `Agent plugin "${name}" is already registered`,
            };
        }

        // Build agent definition compatible with swarm registry format
        const agentDef = {
            name: name,
            type: 'custom',
            category: pluginConfig.category || 'custom',
            description: pluginConfig.description,
            prompt_template: pluginConfig.prompt_template,
            trigger: pluginConfig.trigger || null,
            quality_gate: pluginConfig.quality_gate || false,
            capabilities: pluginConfig.capabilities || [],
            registered_at: new Date().toISOString(),
        };

        _registeredAgents.set(name, agentDef);

        // If an external registry object is provided, add to its custom category
        if (registry && typeof registry === 'object') {
            if (registry.customAgents) {
                registry.customAgents[name] = agentDef;
            }
        }

        return { success: true };
    }

    /**
     * Unregister a custom agent plugin.
     *
     * @param {string} pluginName - Name of the agent plugin to remove
     * @param {object} [registry] - Optional external registry to also remove from
     * @returns {{ success: boolean, error?: string }}
     */
    static unregister(pluginName, registry) {
        if (!_registeredAgents.has(pluginName)) {
            return { success: false, error: `Agent plugin "${pluginName}" is not registered` };
        }

        _registeredAgents.delete(pluginName);

        if (registry && registry.customAgents) {
            delete registry.customAgents[pluginName];
        }

        return { success: true };
    }

    /**
     * List all registered custom agent plugins.
     *
     * @returns {object[]} Array of agent definitions
     */
    static listRegistered() {
        return Array.from(_registeredAgents.values());
    }

    /**
     * Get a specific registered agent plugin by name.
     *
     * @param {string} name - Agent plugin name
     * @returns {object|null} Agent definition or null
     */
    static get(name) {
        return _registeredAgents.get(name) || null;
    }

    /**
     * Check if a custom agent is registered.
     *
     * @param {string} name - Agent name
     * @returns {boolean}
     */
    static isRegistered(name) {
        return _registeredAgents.has(name);
    }

    /**
     * Clear all registered custom agents (primarily for testing).
     */
    static _clearAll() {
        _registeredAgents.clear();
    }
}

module.exports = { AgentPlugin };

'use strict';

const { execFile } = require('child_process');
const { join } = require('path');

// In-memory registry for custom gate plugins
const _registeredGates = new Map();

class GatePlugin {
    /**
     * Register a custom quality gate plugin.
     *
     * @param {object} pluginConfig - Validated quality gate plugin config
     * @returns {{ success: boolean, error?: string }}
     */
    static register(pluginConfig) {
        if (!pluginConfig || pluginConfig.type !== 'quality_gate') {
            return { success: false, error: 'Invalid plugin config: type must be "quality_gate"' };
        }

        const name = pluginConfig.name;

        if (_registeredGates.has(name)) {
            return { success: false, error: `Gate plugin "${name}" is already registered` };
        }

        const gateDef = {
            name: name,
            description: pluginConfig.description,
            phase: pluginConfig.phase || 'pre-commit',
            command: pluginConfig.command,
            timeout_ms: pluginConfig.timeout_ms || 30000,
            blocking: pluginConfig.blocking !== undefined ? pluginConfig.blocking : true,
            severity: pluginConfig.severity || 'high',
            registered_at: new Date().toISOString(),
        };

        _registeredGates.set(name, gateDef);
        return { success: true };
