const SHELL_INJECTION_PATTERN = /[|;&`<>]|\$\(|`.*`|\$\{(?!ENV_)|\n|\r/;

// Allowed template variable patterns
const ALLOWED_TEMPLATE_PATTERNS = [
    /\{\{event\.\w+(\.\w+)*\}\}/,   // {{event.type}}, {{event.data.field}}
    /\$\{ENV_[A-Z_]+\}/,             // ${ENV_VAR_NAME}
];

// Valid plugin types
const VALID_PLUGIN_TYPES = ['agent', 'quality_gate', 'integration', 'mcp_tool'];

// Schema file mapping
const SCHEMA_FILES = {
    agent: 'agent.json',
    quality_gate: 'quality_gate.json',
    integration: 'integration.json',
    mcp_tool: 'mcp_tool.json',
};

class PluginValidator {
    /**
     * Create a new PluginValidator.
     * @param {string} schemasDir - Path to the schemas directory
     */
    constructor(schemasDir) {
        this.schemasDir = schemasDir || join(__dirname, 'schemas');
        this._schemaCache = {};
    }

    /**
     * Load a JSON schema for a plugin type.
     * @param {string} pluginType - The plugin type
     * @returns {object|null} The parsed schema or null
     */
    _loadSchema(pluginType) {
        if (this._schemaCache[pluginType]) {
            return this._schemaCache[pluginType];
        }

        const schemaFile = SCHEMA_FILES[pluginType];
        if (!schemaFile) {
            return null;
        }

        try {
            const schemaPath = join(this.schemasDir, schemaFile);
            const content = readFileSync(schemaPath, 'utf8');
            const schema = JSON.parse(content);
            this._schemaCache[pluginType] = schema;
            return schema;
        } catch (err) {
            return null;
        }
    }

    /**
     * Validate a plugin configuration.
     * @param {object} pluginConfig - The plugin configuration to validate
     * @returns {{ valid: boolean, errors: string[] }}
     */
    validate(pluginConfig) {
        const errors = [];

        // 1. Check that config is an object
        if (!pluginConfig || typeof pluginConfig !== 'object' || Array.isArray(pluginConfig)) {
            return { valid: false, errors: ['Plugin config must be a non-null object'] };
        }

        // 2. Check required base fields
        if (!pluginConfig.type) {
            errors.push('Missing required field: type');
        }
        if (!pluginConfig.name) {
            errors.push('Missing required field: name');
        }

        // If we cannot determine type, return early
        if (!pluginConfig.type) {
            return { valid: false, errors };
        }

        // 3. Check plugin type is valid
        if (!VALID_PLUGIN_TYPES.includes(pluginConfig.type)) {
            errors.push(`Unknown plugin type: "${pluginConfig.type}". Valid types: ${VALID_PLUGIN_TYPES.join(', ')}`);
            return { valid: false, errors };
        }

        // 4. Load and validate against schema
        const schema = this._loadSchema(pluginConfig.type);
        if (schema) {
            const schemaErrors = this._validateAgainstSchema(pluginConfig, schema);
            errors.push(...schemaErrors);
        }

        // 5. Security checks
        const securityErrors = this._securityChecks(pluginConfig);
        errors.push(...securityErrors);

        // 6. Built-in name collision check (for agents)
        if (pluginConfig.type === 'agent' && pluginConfig.name) {
            if (BUILTIN_AGENT_NAMES.includes(pluginConfig.name)) {
                errors.push(`Name "${pluginConfig.name}" conflicts with a built-in agent type. Custom agents must use unique names.`);
            }
        }

        return { valid: errors.length === 0, errors };
    }

    /**
     * Validate config against a JSON schema (simplified validator).
     * @param {object} config - The config to validate
     * @param {object} schema - The JSON schema
     * @returns {string[]} List of validation errors
     */
    _validateAgainstSchema(config, schema) {
        const errors = [];

        // Check required fields
        if (schema.required && Array.isArray(schema.required)) {
            for (const field of schema.required) {
                if (config[field] === undefined || config[field] === null || config[field] === '') {
                    errors.push(`Missing required field: ${field}`);
                }
            }
        }

        // Check property types and constraints
        if (schema.properties) {
            for (const [key, propSchema] of Object.entries(schema.properties)) {
                const value = config[key];
                if (value === undefined || value === null) {
                    continue; // Skip if not present (required check above handles that)
                }

                // Type check
                if (propSchema.type) {
                    const typeValid = this._checkType(value, propSchema.type);
                    if (!typeValid) {
                        errors.push(`Field "${key}" must be of type ${propSchema.type}, got ${typeof value}`);
                        continue;
                    }
                }

                // Const check
                if (propSchema.const !== undefined && value !== propSchema.const) {
                    errors.push(`Field "${key}" must be "${propSchema.const}"`);
                }

                // Enum check
                if (propSchema.enum && !propSchema.enum.includes(value)) {
                    errors.push(`Field "${key}" must be one of: ${propSchema.enum.join(', ')}`);
                }

                // Pattern check (string)
                if (propSchema.pattern && typeof value === 'string') {
                    const regex = new RegExp(propSchema.pattern);
                    if (!regex.test(value)) {
                        errors.push(`Field "${key}" does not match pattern ${propSchema.pattern}`);
                    }
                }

                // MaxLength check (string)
                if (propSchema.maxLength !== undefined && typeof value === 'string') {
                    if (value.length > propSchema.maxLength) {
                        errors.push(`Field "${key}" exceeds maximum length of ${propSchema.maxLength} (got ${value.length})`);
                    }
                }

                // MinItems check (array)
                if (propSchema.minItems !== undefined && Array.isArray(value)) {
                    if (value.length < propSchema.minItems) {
                        errors.push(`Field "${key}" must have at least ${propSchema.minItems} items`);
                    }
                }

                // Minimum check (integer/number)
                if (propSchema.minimum !== undefined && typeof value === 'number') {
                    if (value < propSchema.minimum) {
                        errors.push(`Field "${key}" must be >= ${propSchema.minimum}`);
                    }
                }

                // Maximum check (integer/number)
                if (propSchema.maximum !== undefined && typeof value === 'number') {
                    if (value > propSchema.maximum) {
                        errors.push(`Field "${key}" must be <= ${propSchema.maximum}`);
                    }
                }
            }

            // Check for additional properties (if additionalProperties is false)
            if (schema.additionalProperties === false) {
                const allowedKeys = Object.keys(schema.properties);
                for (const key of Object.keys(config)) {
                    if (!allowedKeys.includes(key)) {
                        errors.push(`Unknown field: "${key}" is not allowed`);
                    }
                }
            }
        }

        return errors;
    }

    /**
     * Check if a value matches a JSON schema type.
     * @param {*} value - The value to check
     * @param {string} type - The expected type
     * @returns {boolean}
     */
    _checkType(value, type) {
        switch (type) {
            case 'string':
                return typeof value === 'string';
            case 'number':
            case 'integer':
                return typeof value === 'number' && (type !== 'integer' || Number.isInteger(value));
            case 'boolean':
                return typeof value === 'boolean';
            case 'array':
                return Array.isArray(value);
            case 'object':
                return typeof value === 'object' && !Array.isArray(value) && value !== null;
            default:
                return true;
        }
    }

    /**
     * Run security checks on a plugin config.
     * @param {object} config - The plugin configuration
     * @returns {string[]} List of security errors
     */
    _securityChecks(config) {
        const errors = [];

        // Check command fields for shell injection
        const commandFields = ['command'];
        for (const field of commandFields) {
            if (typeof config[field] === 'string') {
                if (SHELL_INJECTION_PATTERN.test(config[field])) {
                    errors.push(`Security: field "${field}" contains potentially dangerous shell metacharacters (|, ;, &, $(), backticks). Use simple commands only.`);
                }
            }
        }

        // Check prompt_template for size and suspicious patterns
        if (typeof config.prompt_template === 'string') {
            if (config.prompt_template.length > 10000) {
                errors.push(`Field "prompt_template" exceeds maximum length of 10000`);
            }
        }

        // Check payload_template for injection
        if (typeof config.payload_template === 'string') {
            // Scan for template variables that are not in the allowed list
            const templateVarPattern = /\{\{(?!event\.)[^}]+\}\}/g;
            const disallowed = config.payload_template.match(templateVarPattern);
            if (disallowed && disallowed.length > 0) {
                errors.push(`Security: payload_template contains disallowed template variables: ${disallowed.join(', ')}. Only {{event.*}} patterns are allowed.`);
            }
        }

        // Check webhook_url is HTTPS or localhost
        if (typeof config.webhook_url === 'string') {
            const url = config.webhook_url.toLowerCase();
            if (!url.startsWith('https://') && !url.startsWith('http://localhost') && !url.startsWith('http://127.0.0.1')) {
                errors.push('Security: webhook_url must use HTTPS or localhost');
            }
        }

        return errors;
    }
}

module.exports = { PluginValidator, BUILTIN_AGENT_NAMES, VALID_PLUGIN_TYPES };

'use strict';

/**
 * Sognatore Policy Engine - Approval Gate System
 *
 * Manages configurable approval breakpoints that pause execution
 * at specified phases.
 *
 * Features:
 *   - Configurable breakpoints by phase name
 *   - Webhook callback for async approval (POST to configured URL)
 *   - Auto-approve after configurable timeout (default: 30 minutes)
 *   - Approval state persisted to .sognatore/state/approvals.json
 *   - Full audit trail of all approval decisions
 *
 * The webhook is fire-and-forget: POST is sent and response handled async.
 */

const fs = require('fs');
const path = require('path');
const http = require('http');
const https = require('https');
const crypto = require('crypto');

// -------------------------------------------------------------------
// Constants
// -------------------------------------------------------------------

const DEFAULT_TIMEOUT_MINUTES = 30;
const APPROVAL_STATES = ['pending', 'approved', 'rejected', 'timed_out'];

// -------------------------------------------------------------------
// SSRF protection helpers
// -------------------------------------------------------------------

/**
 * Returns true if the hostname resolves to an internal/private address.
 * Checks against RFC1918, loopback, and link-local ranges by hostname
 * string matching (does not perform DNS resolution).
 */
function _isInternalHostname(hostname) {
  // Reject loopback
  if (hostname === 'localhost' || hostname === '127.0.0.1' || hostname === '::1') return true;

  // Reject link-local (169.254.x.x)
  if (/^169\.254\./.test(hostname)) return true;

  // Reject RFC1918 private ranges
  if (/^10\./.test(hostname)) return true;
  if (/^192\.168\./.test(hostname)) return true;
  if (/^172\.(1[6-9]|2[0-9]|3[0-1])\./.test(hostname)) return true;

  // Reject IPv6 private/loopback
  if (/^(::1|fc[0-9a-f]{2}:|fd[0-9a-f]{2}:)/i.test(hostname)) return true;

  return false;
}

/**
 * Validate a webhook URL for SSRF safety.
 * Returns an error string if invalid, null if valid.
 */
function _validateWebhookUrl(url) {
  let parsed;
  try {
    parsed = new URL(url);
  } catch (_) {
    return 'Invalid webhook URL';
  }
  if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
    return 'Webhook URL must use http or https protocol, got: ' + parsed.protocol;
  }
  if (_isInternalHostname(parsed.hostname)) {
    return 'Webhook URL must not target internal/private addresses';
  }
  return null;
}

// -------------------------------------------------------------------
// ApprovalGateManager class
// -------------------------------------------------------------------

/** Maximum audit entries to prevent unbounded state file growth. */
const MAX_AUDIT_ENTRIES = 10000;

class ApprovalGateManager {
  /**
   * @param {string} projectDir - Root directory containing .sognatore/
   * @param {Array} gates - Array of gate definitions from policies
   */
  constructor(projectDir, gates) {
    this._projectDir = projectDir || process.cwd();
    this._gates = gates || [];
    this._stateFile = path.join(this._projectDir, '.sognatore', 'state', 'approvals.json');
    this._state = this._loadState();
    this._pendingTimers = {};
  }

  // -----------------------------------------------------------------
  // State persistence
  // -----------------------------------------------------------------

  _loadState() {
    try {
      if (fs.existsSync(this._stateFile)) {
        const raw = fs.readFileSync(this._stateFile, 'utf8');
        return JSON.parse(raw);
      }
    } catch (_) {
      // Corrupted state file -- start fresh
    }
    return { requests: [], audit: [] };
  }

  _saveState() {
    const dir = path.dirname(this._stateFile);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }
    fs.writeFileSync(this._stateFile, JSON.stringify(this._state, null, 2), 'utf8');
  }

  // -----------------------------------------------------------------
  // Gate lookup
  // -----------------------------------------------------------------

  /**
   * Find the gate definition for a given phase.
   */
  findGate(phase) {
    for (let i = 0; i < this._gates.length; i++) {
      if (this._gates[i].phase === phase) {
        return this._gates[i];
      }
    }
    return null;
  }

  /**
   * Check if a phase requires an approval gate.
   */
  hasGate(phase) {
    return this.findGate(phase) !== null;
  }

  // -----------------------------------------------------------------
  // Request approval
  // -----------------------------------------------------------------

  /**
   * Request approval for a gate. Returns a Promise that resolves when
   * approved/rejected/timed-out.
   *
   * @param {string} phase - The phase name (e.g., "deploy")
   * @param {object} context - Contextual data about the request
   * @returns {Promise<{approved: boolean, reason: string, method: string}>}
   */
  requestApproval(phase, context) {
    const gate = this.findGate(phase);
    if (!gate) {
      // No gate for this phase -- auto-approve
      return Promise.resolve({
        approved: true,
        reason: 'No approval gate configured for phase: ' + phase,
        method: 'auto',
      });
    }

    const requestId = 'apr-' + crypto.randomBytes(16).toString('hex');
    const timeout = (gate.timeout_minutes || DEFAULT_TIMEOUT_MINUTES) * 60 * 1000;

    const request = {
      id: requestId,
      phase: phase,
      gate: gate.name,
      status: 'pending',
      context: context || {},
      createdAt: new Date().toISOString(),
      resolvedAt: null,
      method: null,
      reason: null,
    };

    this._state.requests.push(request);
    this._saveState();

    // Fire webhook (fire-and-forget)
    if (gate.webhook) {
      this._sendWebhook(gate.webhook, request);
    }

    const self = this;

    return new Promise(function (resolve) {
      // Set timeout handler.
      // Default behavior (fail-closed): timeout resolves as rejected (approved: false).
      // Opt-in to auto-approve on timeout by setting gate.auto_approve_on_timeout: true.
      const autoApproveOnTimeout = gate.auto_approve_on_timeout === true;
      const timer = setTimeout(function () {
        delete self._pendingTimers[requestId];
        request.status = 'timed_out';
        request.resolvedAt = new Date().toISOString();
        request.method = 'timeout';
        if (autoApproveOnTimeout) {
          request.reason = 'Auto-approved after ' + (gate.timeout_minutes || DEFAULT_TIMEOUT_MINUTES) + ' minute timeout';
        } else {
          request.reason = 'Rejected: approval not received within ' + (gate.timeout_minutes || DEFAULT_TIMEOUT_MINUTES) + ' minute timeout';
        }
        self._addAudit(request);
        self._saveState();
        resolve({
          approved: autoApproveOnTimeout,
          reason: request.reason,
          method: 'timeout',
        });
      }, timeout);

      // Store resolver so external approval can trigger it
      self._pendingTimers[requestId] = {
        timer: timer,
        resolve: resolve,
        request: request,
      };
    });
  }

  /**
   * Resolve a pending approval externally (e.g., via webhook callback).
   *
   * @param {string} requestId - The approval request ID
   * @param {boolean} approved - Whether to approve or reject
   * @param {string} [reason] - Reason for the decision
   * @returns {boolean} - Whether the request was found and resolved
   */
  resolveApproval(requestId, approved, reason) {
    const pending = this._pendingTimers[requestId];
    if (!pending) return false;

    clearTimeout(pending.timer);
    delete this._pendingTimers[requestId];

    const request = pending.request;
    request.status = approved ? 'approved' : 'rejected';
    request.resolvedAt = new Date().toISOString();
    request.method = 'manual';
    request.reason = reason || (approved ? 'Manually approved' : 'Manually rejected');

    this._addAudit(request);
    this._saveState();

    pending.resolve({
      approved: approved,
      reason: request.reason,
      method: 'manual',
    });

    return true;
  }

  // -----------------------------------------------------------------
  // Webhook
  // -----------------------------------------------------------------

  _sendWebhook(url, request) {
    try {
      // Validate URL for SSRF safety before making any outbound request
      const urlError = _validateWebhookUrl(url);
      if (urlError) {
        // Silently drop invalid webhook -- caller already validated at config load
        return;
      }

      const payload = JSON.stringify({
        type: 'approval_request',
        id: request.id,
        phase: request.phase,
        gate: request.gate,
        context: request.context,
        createdAt: request.createdAt,
      });

      const parsed = new URL(url);
      const transport = parsed.protocol === 'https:' ? https : http;

      const opts = {
        hostname: parsed.hostname,
        port: parsed.port || (parsed.protocol === 'https:' ? 443 : 80),
        path: parsed.pathname + parsed.search,
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(payload),
        },
        timeout: 5000,
      };

      const req = transport.request(opts, function () {
        // Fire-and-forget: ignore response
      });
      req.on('error', function () {
        // Silently ignore webhook failures
      });
      req.write(payload);
      req.end();
    } catch (_) {
      // Ignore any errors in webhook sending
    }
  }

  // -----------------------------------------------------------------
  // Audit trail
  // -----------------------------------------------------------------

  _addAudit(request) {
    if (this._state.audit.length >= MAX_AUDIT_ENTRIES) {
      this._state.audit.splice(0, this._state.audit.length - MAX_AUDIT_ENTRIES + 1);
    }
    this._state.audit.push({
      id: request.id,
      phase: request.phase,
      gate: request.gate,
      status: request.status,
      method: request.method,
      reason: request.reason,
      createdAt: request.createdAt,
      resolvedAt: request.resolvedAt,
    });
  }

  /**
   * Get the full audit trail.
   */
  getAuditTrail() {
    return this._state.audit.slice();
  }

  /**
   * Get all pending requests.
   */
  getPendingRequests() {
    return this._state.requests.filter(function (r) {
      return r.status === 'pending';
    });
  }

  // -----------------------------------------------------------------
  // Cleanup
  // -----------------------------------------------------------------

  /**
   * Cancel all pending timers and clean up.
   */
  destroy() {
    const ids = Object.keys(this._pendingTimers);
    for (let i = 0; i < ids.length; i++) {
      clearTimeout(this._pendingTimers[ids[i]].timer);
    }
    this._pendingTimers = {};
  }
}

// -------------------------------------------------------------------
// Exports
// -------------------------------------------------------------------

module.exports = { ApprovalGateManager, DEFAULT_TIMEOUT_MINUTES, APPROVAL_STATES };

#!/usr/bin/env node
'use strict';

var PolicyEngine = require('./engine').PolicyEngine;

var enforcementPoint = process.argv[2];
if (!enforcementPoint) {
    process.stderr.write('Usage: node check.js <enforcement_point> [context_json]\n');
    process.exit(1);
}

var context = {};
if (process.argv[3]) {
    try {
        context = JSON.parse(process.argv[3]);
    } catch (e) {
        process.stderr.write('Invalid context JSON: ' + e.message + '\n');
        process.exit(1);
    }
}

var projectDir = process.env.SOGNATORE_PROJECT_DIR || process.cwd();
var engine;
try {
    engine = new PolicyEngine(projectDir);
} catch (e) {
    // No policies configured - allow by default
    process.stdout.write(JSON.stringify({ allowed: true, decision: 'ALLOW', reason: 'No policies configured' }));
    process.exit(0);
}

var result = engine.evaluate(enforcementPoint, context);
process.stdout.write(JSON.stringify(result));

if (!result.allowed) {
    process.exit(result.requiresApproval ? 2 : 1);
}
process.exit(0);

'use strict';

/**
 * Sognatore Policy Engine - Cost Control System
 *
 * Per-project token budget tracking with configurable alert thresholds.
 *
 * Features:
 *   - Per-project token budget tracking
 *   - Alerts at configurable thresholds (default: 50%, 80%, 100%)
 *   - Per-agent cost tracking (model type, tokens consumed, duration)
 *   - Kill switch: emits shutdown event when budget exceeded
 *   - Cost data persisted to .sognatore/state/costs.json
 */

const fs = require('fs');
const path = require('path');
const { EventEmitter } = require('events');

// -------------------------------------------------------------------
// CostController class
// -------------------------------------------------------------------

/** Maximum entries per project in state file to prevent unbounded growth. */
const MAX_STATE_ENTRIES = 10000;

class CostController extends EventEmitter {
  /**
   * @param {string} projectDir - Root directory containing .sognatore/
   * @param {Array} resourcePolicies - Resource policy entries from engine
   */
  constructor(projectDir, resourcePolicies) {
    super();
    this._projectDir = projectDir || process.cwd();
    this._stateFile = path.join(this._projectDir, '.sognatore', 'state', 'costs.json');
    this._state = this._loadState();
    this._budgetConfig = this._extractBudgetConfig(resourcePolicies || []);
    this._triggeredAlerts = new Set();
    // Per-project shutdown flags (keyed by projectId or 'global').
    // Using a Set instead of a single boolean ensures each project only
    // emits shutdown once even when multiple projects are tracked.
    this._shutdownEmittedProjects = new Set();

    // Restore previously triggered alerts
    if (this._state.triggeredAlerts) {
      for (let i = 0; i < this._state.triggeredAlerts.length; i++) {
        this._triggeredAlerts.add(this._state.triggeredAlerts[i]);
      }
    }
  }

  // -----------------------------------------------------------------
  // State persistence
  // -----------------------------------------------------------------

  _loadState() {
    try {
      if (fs.existsSync(this._stateFile)) {
        const raw = fs.readFileSync(this._stateFile, 'utf8');
        return JSON.parse(raw);
      }
    } catch (_) {
      // Corrupted file -- start fresh
    }
    return {
      projects: {},
      agents: {},
      totalTokens: 0,
      triggeredAlerts: [],
      history: [],
    };
  }

  _saveState() {
    const dir = path.dirname(this._stateFile);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }
    this._state.triggeredAlerts = Array.from(this._triggeredAlerts);
    fs.writeFileSync(this._stateFile, JSON.stringify(this._state, null, 2), 'utf8');
  }

  _extractBudgetConfig(resourcePolicies) {
    for (let i = 0; i < resourcePolicies.length; i++) {
      const p = resourcePolicies[i];
      if (p.max_tokens) {
        return {
          maxTokens: p.max_tokens,
          alerts: p.alerts || [50, 80, 100],
          onExceed: p.on_exceed || 'shutdown',
          name: p.name,
        };
      }
    }
    return null;
  }

  // -----------------------------------------------------------------
  // Token recording
  // -----------------------------------------------------------------

  /**
   * Record tokens consumed by an agent.
   *
   * @param {string} projectId - Project identifier
   * @param {object} usage - { agentId, model, tokens, durationMs }
   */
  recordUsage(projectId, usage) {
    const { agentId, model, tokens, durationMs } = usage || {};
    const tokenCount = tokens || 0;

    // Update project totals
    if (!this._state.projects[projectId]) {
      this._state.projects[projectId] = { totalTokens: 0, entries: [] };
    }
    this._state.projects[projectId].totalTokens += tokenCount;
    this._state.projects[projectId].entries.push({
      agentId: agentId || 'unknown',
      model: model || 'unknown',
      tokens: tokenCount,
      durationMs: durationMs || 0,
      timestamp: new Date().toISOString(),
    });

    // Update agent totals
    const agentKey = agentId || 'unknown';
    if (!this._state.agents[agentKey]) {
      this._state.agents[agentKey] = { totalTokens: 0, model: model, entries: 0 };
    }
    this._state.agents[agentKey].totalTokens += tokenCount;
    this._state.agents[agentKey].entries += 1;

    // Update global total
    this._state.totalTokens += tokenCount;

    // Check alerts and budget
    this._checkAlerts(projectId);

    this._saveState();
  }

  // -----------------------------------------------------------------
  // Budget checking
  // -----------------------------------------------------------------

  /**
   * Check the budget status for a project (or globally).
   *
   * @param {string} [projectId] - Project identifier (if omitted, checks global)
   * @returns {{ remaining: number, percentage: number, alerts: Array, exceeded: boolean }}
   */
  checkBudget(projectId) {
    if (!this._budgetConfig) {
      return {
        remaining: Infinity,
        percentage: 0,
        alerts: [],
        exceeded: false,
      };
    }

    const consumed = projectId && this._state.projects[projectId]
      ? this._state.projects[projectId].totalTokens
      : this._state.totalTokens;

    const max = this._budgetConfig.maxTokens;
    const percentage = max > 0 ? Math.round((consumed / max) * 100) : 0;
    const remaining = Math.max(0, max - consumed);
    const exceeded = consumed >= max;

    // Collect active alerts
    const alerts = [];
    const thresholds = this._budgetConfig.alerts;
    for (let i = 0; i < thresholds.length; i++) {
      if (percentage >= thresholds[i]) {
        alerts.push({
          threshold: thresholds[i],
          message: 'Token usage at ' + percentage + '% (threshold: ' + thresholds[i] + '%)',
        });
      }
    }

    return { remaining, percentage, alerts, exceeded };
  }

  _checkAlerts(projectId) {
    if (!this._budgetConfig) return;

    const budget = this.checkBudget(projectId);

    // Emit alert events for newly triggered thresholds
    const thresholds = this._budgetConfig.alerts;
    for (let i = 0; i < thresholds.length; i++) {
      const key = (projectId || 'global') + ':' + thresholds[i];
      if (budget.percentage >= thresholds[i] && !this._triggeredAlerts.has(key)) {
        this._triggeredAlerts.add(key);

        if (this._state.history.length > MAX_STATE_ENTRIES) {
      this._state.history.splice(0, this._state.history.length - MAX_STATE_ENTRIES);
    }
    this._state.history.push({
          type: 'alert',
          threshold: thresholds[i],
          percentage: budget.percentage,
          projectId: projectId || 'global',
          timestamp: new Date().toISOString(),
        });

        this.emit('alert', {
          threshold: thresholds[i],
          percentage: budget.percentage,
          projectId: projectId,
          remaining: budget.remaining,
        });
      }
    }

    // Kill switch (per-project: each project emits shutdown at most once)
    const shutdownKey = projectId || 'global';
    if (budget.exceeded && !this._shutdownEmittedProjects.has(shutdownKey)) {
      if (this._budgetConfig.onExceed === 'shutdown') {
        this._shutdownEmittedProjects.add(shutdownKey);

        if (this._state.history.length > MAX_STATE_ENTRIES) {
      this._state.history.splice(0, this._state.history.length - MAX_STATE_ENTRIES);
    }
    this._state.history.push({
          type: 'shutdown',
          reason: 'Budget exceeded',
          percentage: budget.percentage,
          projectId: projectId || 'global',
          timestamp: new Date().toISOString(),
        });

        this._saveState();
        this.emit('shutdown', {
          reason: 'Token budget exceeded',
          projectId: projectId,
          percentage: budget.percentage,
          consumed: this._state.totalTokens,
          max: this._budgetConfig.maxTokens,
        });
      }
    }
  }

  // -----------------------------------------------------------------
  // Reporting
  // -----------------------------------------------------------------

  /**
   * Get per-agent cost report.
   */
  getAgentReport() {
    return Object.assign({}, this._state.agents);
  }

  /**
   * Get per-project cost report.
   */
  getProjectReport(projectId) {
    if (projectId) {
      return this._state.projects[projectId] || null;
    }
    return Object.assign({}, this._state.projects);
  }

  /**
   * Get the history of alerts and shutdown events.
   */
  getHistory() {
    return this._state.history.slice();
  }

  /**
   * Reset all cost tracking data.
   */
  reset() {
    this._state = {
      projects: {},
      agents: {},
      totalTokens: 0,
      triggeredAlerts: [],
      history: [],
    };
    this._triggeredAlerts.clear();
    this._shutdownEmittedProjects.clear();
    this._saveState();
  }
}

